import React from "react";

export const mappedAriaRolesToAdditionalDescriptions = {
  alert: (
    <>
      <p>{"See related alertdialog and status."}</p>
      <p dangerouslySetInnerHTML={{ __html: "Alerts are used to convey messages that will be immediately important to users. In the case of audio warnings, visibly displayed alerts provide an accessible alternative to audible alerts for Deaf or hard-of-hearing users. Likewise, alerts can provide an accessible alternative to the visible alerts for blind, deaf-blind, or low-vision users, and others with certain developmental disabilities. The <code>alert</code> <a href=\"#dfn-role\">role</a> is applied to the element containing the alert message." }} />
      <p dangerouslySetInnerHTML={{ __html: "Alert is a special type of assertive live region that is intended to cause immediate notification for assistive technology users. If the operating system allows, the <a href=\"https://infra.spec.whatwg.org/#user-agent\">user agent</a> <em>SHOULD</em> fire a system alert <a href=\"#dfn-event\">event</a> through the accessibility <abbr title=\"Application Programming Interface\">API</abbr> when the alert is rendered." }} />
      <p dangerouslySetInnerHTML={{ __html: "Neither authors nor user agents are required to set or manage focus to an alert in order for it to be processed. Since alerts are not required to receive focus, authors <em>SHOULD NOT</em> require users to close an alert. If an author desires focus to move to a message when it is conveyed, the author <em>SHOULD</em> use <a href=\"https://w3c.github.io/aria/#alertdialog\"><code>alertdialog</code></a> instead of <code>alert</code>." }} />
      <p dangerouslySetInnerHTML={{ __html: "Elements with the role <code>alert</code> have an implicit <a href=\"https://w3c.github.io/aria/#aria-live\"><code>aria-live</code></a> value of <code>assertive</code>, and an implicit <a href=\"https://w3c.github.io/aria/#aria-atomic\"><code>aria-atomic</code></a> value of <code>true</code>." }} />
    </>
  ),
  alertdialog: (
    <>
      <p>{"See related alert and dialog."}</p>
      <p dangerouslySetInnerHTML={{ __html: "Alert dialogs are used to convey messages to alert the user. The <code>alertdialog</code> <a href=\"#dfn-role\">role</a> goes on the <a href=\"https://dom.spec.whatwg.org/#concept-node\">node</a> containing both the alert message and the rest of the dialog. Authors <em>SHOULD</em> make alert dialogs modal by ensuring that, while the <code>alertdialog</code> is shown, keyboard and mouse interactions only operate within the dialog. See <a href=\"https://w3c.github.io/aria/#aria-modal\"><code>aria-modal</code></a>." }} />
      <p dangerouslySetInnerHTML={{ __html: "Alertdialog is a special type of dialog that is intended to cause an immediate, alert-level notification for assistive technology users. If the operating system allows, the <a href=\"https://infra.spec.whatwg.org/#user-agent\">user agent</a> <em>SHOULD</em> fire a system alert <a href=\"#dfn-event\">event</a> through the accessibility <abbr title=\"Application Programming Interface\">API</abbr> when the alert dialog is rendered." }} />
      <p dangerouslySetInnerHTML={{ __html: "Unlike <a href=\"https://w3c.github.io/aria/#alert\"><code>alert</code></a>, <code>alertdialog</code> can receive a response from the user. For example, to confirm that the user understands the alert being generated. When the alert dialog is displayed, authors <em>SHOULD</em> set focus to an active element within the alert dialog, such as a form control or confirmation button. The <a href=\"https://infra.spec.whatwg.org/#user-agent\">user agent</a> <em>SHOULD</em> fire a system alert <a href=\"#dfn-event\">event</a> through the accessibility <abbr title=\"Application Programming Interface\">API</abbr> when the alert is created, provided one is specified by the intended <a href=\"#dfn-accessibility-api\">accessibility <abbr title=\"Application Programming Interface\">API</abbr></a>." }} />
      <p dangerouslySetInnerHTML={{ __html: "Authors <em>SHOULD</em> provide an accessible name for an <code>alertdialog</code>, which can be done with the <a href=\"https://w3c.github.io/aria/#aria-label\"><code>aria-label</code></a> or <a href=\"https://w3c.github.io/aria/#aria-labelledby\"><code>aria-labelledby</code></a> attribute." }} />
      <p dangerouslySetInnerHTML={{ __html: "Authors <em>SHOULD</em> use <a href=\"https://w3c.github.io/aria/#aria-describedby\"><code>aria-describedby</code></a> on an <code>alertdialog</code> to reference the alert message element in the dialog. If they do not, an <a href=\"#assistive-technology\">assistive technology</a> can resort to its internal recovery mechanism to determine the contents of the alert message." }} />
    </>
  ),
  application: (
    <>
      <p dangerouslySetInnerHTML={{ __html: "Some <a href=\"https://infra.spec.whatwg.org/#user-agent\">user agents</a> and <a href=\"#assistive-technology\">assistive technologies</a> have a browse mode where standard input events, such as up and down arrow key events, are intercepted and used to control a reading cursor. This browse mode behavior prevents elements that do not have a <a href=\"https://w3c.github.io/aria/#widget\"><code>widget</code></a> role from receiving and using such keyboard and gesture events to provide interactive functionality." }} />
      <p dangerouslySetInnerHTML={{ __html: "When there is a need to create an element with an interaction model that is not supported by any of the <abbr title=\"Accessible Rich Internet Applications\">WAI-ARIA</abbr> <a href=\"https://w3c.github.io/aria/#widget\"><code>widget</code></a> roles, authors <em>MAY</em> give that element role <code>application</code>. And, when a user navigates into an element with role <code>application</code>, <a href=\"#assistive-technology\">assistive technologies</a> that intercept standard input events <em>SHOULD</em> switch to a mode that passes most or all standard input events through to the web application." }} />
      <p dangerouslySetInnerHTML={{ __html: "For example, a presentation slide editor uses arrow keys to change the positions of textbox and image elements on the slide. There are not any <abbr title=\"Accessible Rich Internet Application\">WAI-ARIA</abbr> <a href=\"https://w3c.github.io/aria/#widget\"><code>widget</code></a> roles that correspond to such an interaction model so an author could give the slide container role <code>application</code>, an <a href=\"https://w3c.github.io/aria/#aria-roledescription\"><code>aria-roledescription</code></a> of \"Slide Editor\", and use <a href=\"https://w3c.github.io/aria/#aria-describedby\"><code>aria-describedby</code></a> to provide instructions." }} />
      <p dangerouslySetInnerHTML={{ __html: "Because only the focusable elements contained in an <code>application</code> element are accessible to users of some assistive technologies, authors <em>MUST</em> use one of the following techniques to ensure all non-decorative static text or image content inside an application is accessible:" }} />
    </>
  ),
  article: (
    <>
      <p dangerouslySetInnerHTML={{ __html: "An article is not a navigational <a href=\"#dfn-landmark\">landmark</a>, but can be nested to form a discussion where assistive technologies could pay attention to article nesting to assist the user in following the discussion. An article could be a forum post, a magazine or newspaper article, a web log entry, a user-submitted comment, or any other independent item of content. It is <em>independent</em> in that its contents could stand alone, for example in syndication. However, the <a href=\"https://dom.spec.whatwg.org/#concept-element\">element</a> is still associated with its ancestors; for instance, contact information that applies to a parent body element still covers the article as well. When nesting articles, the child articles represent content that is related to the content of the parent article. For instance, a web log entry on a site that accepts user-submitted comments could represent the comments as articles nested within the article for the web log entry. Author, heading, date, or other information associated with an article does not apply to nested articles." }} />
      <p dangerouslySetInnerHTML={{ __html: "When the user navigates to an element assigned the role of <code>article</code>, <a href=\"#assistive-technology\">assistive technologies</a> that typically intercept standard keyboard events <em>SHOULD</em> switch to document browsing mode, as opposed to passing keyboard events through to the web application. Some assistive technologies provide a feature allowing the user to navigate the hierarchy of any nested <code>article</code> elements." }} />
      <p dangerouslySetInnerHTML={{ __html: "When an <code>article</code> is in the context of a <a href=\"https://w3c.github.io/aria/#feed\"><code>feed</code></a>, the author <em>MAY</em> specify values for <a href=\"https://w3c.github.io/aria/#aria-posinset\"><code>aria-posinset</code></a> and <a href=\"https://w3c.github.io/aria/#aria-setsize\"><code>aria-setsize</code></a>." }} />
    </>
  ),
  banner: (
    <>
      <p dangerouslySetInnerHTML={{ __html: "Site-oriented content typically includes things such as the logo or identity of the site sponsor, and a site-specific search tool. A banner usually appears at the top of the page and typically spans the full width." }} />
      <p dangerouslySetInnerHTML={{ __html: "<a href=\"#assistive-technology\">Assistive technologies</a> <em>SHOULD</em> enable users to quickly navigate to elements with role <code>banner</code>. <a href=\"https://infra.spec.whatwg.org/#user-agent\">user agents</a> <em>SHOULD</em> treat elements with role <code>banner</code> as navigational <a href=\"#dfn-landmark\">landmarks</a>. <a href=\"https://infra.spec.whatwg.org/#user-agent\">user agents</a> <em>MAY</em> enable users to quickly navigate to elements with role <code>banner</code>." }} />
      <p dangerouslySetInnerHTML={{ __html: "The author <em>SHOULD</em> mark no more than one <a href=\"https://dom.spec.whatwg.org/#concept-element\">element</a> on a page with the <code>banner</code> <a href=\"#dfn-role\">role</a>." }} />
    </>
  ),
  button: (
    <>
      <p>{"See related link."}</p>
      <p dangerouslySetInnerHTML={{ __html: "Buttons are mostly used for discrete actions. Standardizing the appearance of buttons enhances the user's recognition of the <a href=\"#dfn-widget\">widgets</a> as buttons and allows for a more compact display in toolbars." }} />
      <p dangerouslySetInnerHTML={{ __html: "Buttons support the optional <a href=\"https://dom.spec.whatwg.org/#concept-attribute\">attribute</a> <a href=\"https://w3c.github.io/aria/#aria-pressed\"><code>aria-pressed</code></a>. Buttons with a non-empty <a href=\"https://w3c.github.io/aria/#aria-pressed\"><code>aria-pressed</code></a> attribute are toggle buttons. When <a href=\"https://w3c.github.io/aria/#aria-pressed\"><code>aria-pressed</code></a> is <code>true</code> the button is in a \"pressed\" <a href=\"#dfn-state\">state</a>, when <a href=\"https://w3c.github.io/aria/#aria-pressed\"><code>aria-pressed</code></a> is <code>false</code> it is not pressed. If the attribute is not present, the button is a simple command button." }} />
    </>
  ),
  caption: (
    <>
      <p dangerouslySetInnerHTML={{ __html: "When using <code>caption</code> authors <em>SHOULD</em> ensure:" }} />
      <p dangerouslySetInnerHTML={{ __html: "If the <code>caption</code> represents an accessible name for its containing element, authors <em>SHOULD</em> specify <a href=\"https://w3c.github.io/aria/#aria-labelledby\"><code>aria-labelledby</code></a> on the containing element to reference the element with role <code>caption</code>." }} />
    </>
  ),
  cell: (
    <>
      <p>{"See related gridcell."}</p>
      <p dangerouslySetInnerHTML={{ __html: "Authors <em>MUST</em> ensure <a href=\"https://dom.spec.whatwg.org/#concept-element\">elements</a> with <a href=\"#dfn-role\">role</a> cell are the <a href=\"#dfn-accessibility-child\">accessibility children</a> of an element with the <a href=\"#dfn-role\">role</a> <a href=\"https://w3c.github.io/aria/#row\"><code>row</code></a>." }} />
    </>
  ),
  checkbox: (
    <>
      <p dangerouslySetInnerHTML={{ __html: "The <a href=\"https://w3c.github.io/aria/#aria-checked\"><code>aria-checked</code></a> <a href=\"https://dom.spec.whatwg.org/#concept-attribute\">attribute</a> of a <code>checkbox</code> indicates whether the input is checked (<code>true</code>), unchecked (<code>false</code>), or represents a group of <a href=\"https://dom.spec.whatwg.org/#concept-element\">elements</a> that have a mixture of checked and unchecked values (<code>mixed</code>). Many checkboxes do not use the <code>mixed</code> value, and thus are effectively boolean checkboxes." }} />
    </>
  ),
  code: (
    <>
      <p dangerouslySetInnerHTML={{ __html: "The primary purpose of the code role is to inform assistive technologies that the content is computer code and thus might require special presentation, in particular with respect to synthesized speech. More specifically, screen readers and other tools which provide text-to-speech presentation of content <em>SHOULD</em> prefer full punctuation verbosity to ensure common symbols (e.g., \"-\") are spoken." }} />
    </>
  ),
  columnheader: (
    <>
      <p dangerouslySetInnerHTML={{ __html: "<code>columnheader</code> can be used as a column header in a table or grid. It could also be used in a pie chart to show a similar <a href=\"#dfn-relationship\">relationship</a> in the data." }} />
      <p dangerouslySetInnerHTML={{ __html: "The <code>columnheader</code> establishes a relationship between it and all cells in the corresponding column. It is the structural equivalent to an <abbr title=\"Hypertext Markup Language\">HTML</abbr> <code>th</code> <a href=\"https://dom.spec.whatwg.org/#concept-element\">element</a> with a column scope." }} />
      <p dangerouslySetInnerHTML={{ __html: "Authors <em>MUST</em> ensure <a href=\"https://dom.spec.whatwg.org/#concept-element\">elements</a> with <a href=\"#dfn-role\">role</a> <code>columnheader</code> are the <a href=\"#dfn-accessibility-child\">accessibility children</a> of an element with the role <a href=\"https://w3c.github.io/aria/#row\"><code>row</code></a>." }} />
      <p dangerouslySetInnerHTML={{ __html: "Applying the <a href=\"https://w3c.github.io/aria/#aria-selected\"><code>aria-selected</code></a> state on a columnheader <em>MUST</em> not cause the user agent to automatically propagate the <a href=\"https://w3c.github.io/aria/#aria-selected\"><code>aria-selected</code></a> state to all the cells in the corresponding column. An author <em>MAY</em> choose to propagate selection in this manner depending on the specific application." }} />
      <p dangerouslySetInnerHTML={{ __html: "While the <code>columnheader</code> role can be used in both interactive grids and non-interactive tables, the use of <a href=\"https://w3c.github.io/aria/#aria-readonly\"><code>aria-readonly</code></a> and <a href=\"https://w3c.github.io/aria/#aria-required\"><code>aria-required</code></a> is only applicable to interactive elements. Therefore, authors <em>SHOULD NOT</em> use <a href=\"https://w3c.github.io/aria/#aria-required\"><code>aria-required</code></a> or <a href=\"https://w3c.github.io/aria/#aria-readonly\"><code>aria-readonly</code></a> in a <code>columnheader</code> that descends from a <a href=\"https://w3c.github.io/aria/#table\"><code>table</code></a>, and user agents <em>SHOULD NOT</em> expose either property to <a href=\"#assistive-technology\">assistive technologies</a> unless the <code>columnheader</code> descends from a <a href=\"https://w3c.github.io/aria/#grid\"><code>grid</code></a>." }} />
    </>
  ),
  complementary: (
    <>
      <p>{"The contents of a complementary landmark would be expected to remain meaningful if it were to be separated from the main content it is relevant to."}</p>
      <p dangerouslySetInnerHTML={{ __html: "There are various types of content that would appropriately have this <a href=\"#dfn-role\">role</a>. For example, in the case of a portal, this can include but not be limited to show times, current weather, related articles, or stocks to watch. If the complementary content is completely separable from the main content, it might be appropriate to use a more general role." }} />
      <p dangerouslySetInnerHTML={{ __html: "<a href=\"#assistive-technology\">Assistive technologies</a> <em>SHOULD</em> enable users to quickly navigate to elements with role <code>complementary</code>. <a href=\"https://infra.spec.whatwg.org/#user-agent\">user agents</a> <em>SHOULD</em> treat elements with role <code>complementary</code> as navigational <a href=\"#dfn-landmark\">landmarks</a>. <a href=\"https://infra.spec.whatwg.org/#user-agent\">user agents</a> <em>MAY</em> enable users to quickly navigate to elements with role <code>complementary</code>." }} />
    </>
  ),
  contentinfo: (
    <>
      <p dangerouslySetInnerHTML={{ __html: "Examples of information included in this region of the page are copyrights and links to privacy statements." }} />
      <p dangerouslySetInnerHTML={{ __html: "<a href=\"#assistive-technology\">Assistive technologies</a> <em>SHOULD</em> enable users to quickly navigate to elements with role <code>contentinfo</code>. <a href=\"https://infra.spec.whatwg.org/#user-agent\">user agents</a> <em>SHOULD</em> treat elements with role <code>contentinfo</code> as navigational <a href=\"#dfn-landmark\">landmarks</a>. <a href=\"https://infra.spec.whatwg.org/#user-agent\">user agents</a> <em>MAY</em> enable users to quickly navigate to elements with role <code>contentinfo</code>." }} />
      <p dangerouslySetInnerHTML={{ __html: "The author <em>SHOULD</em> mark no more than one <a href=\"https://dom.spec.whatwg.org/#concept-element\">element</a> on a page with the <code>contentinfo</code> role." }} />
    </>
  ),
  definition: (
    <>
      <p>{"See related term."}</p>
      <p dangerouslySetInnerHTML={{ __html: "Authors <em>MUST</em> identify the <a href=\"https://dom.spec.whatwg.org/#concept-element\">element</a> being defined and assign that element a role of <a href=\"https://w3c.github.io/aria/#term\"><code>term</code></a>." }} />
      <p dangerouslySetInnerHTML={{ __html: "Authors <em>SHOULD NOT</em> use the <code>definition</code> role on interactive elements such as form controls because doing so could prevent users of assistive technologies from interacting with those elements." }} />
    </>
  ),
  deletion: (
    <>
      <p>{"See related insertion."}</p>
      <p dangerouslySetInnerHTML={{ __html: "Deletions are typically used to either mark differences between two versions of content or to designate content suggested for removal in scenarios where multiple people are revising content." }} />
    </>
  ),
  dialog: (
    <>
      <p>{"For HTML pages, the primary application window is the entire web document."}</p>
      <p dangerouslySetInnerHTML={{ __html: "Dialogs are often used to prompt the user to enter or respond to information, or can represent content related to understanding or modifying the content of the primary application window. A dialog that is designed to interrupt workflow and prevent users from interacting with the primary web application is usually modal. See related <a href=\"https://w3c.github.io/aria/#alertdialog\"><code>alertdialog</code></a>. A dialog that allows for the user to switch between interacting with the content of the primary web application and the content the dialog is usually modeless (i.e., non-modal). In lieu of using robust host language features for marking content of the primary web application as <code>inert</code>, authors <em>SHOULD</em> use the <a href=\"https://w3c.github.io/aria/#aria-modal\"><code>aria-modal</code></a> attribute, and constrain focus to dialogs. See the <a href=\"https://www.w3.org/WAI/ARIA/apg/patterns/dialog-modal/\"><abbr title=\"Accessible Rich Internet Application\">WAI-ARIA</abbr> Authoring Practices: Dialog (modal) pattern</a> for additional details on implementing modal dialog design patterns." }} />
      <p dangerouslySetInnerHTML={{ __html: "Authors <em>SHOULD</em> provide an accessible name for a dialog, which can be done with the <a href=\"https://w3c.github.io/aria/#aria-label\"><code>aria-label</code></a> or <a href=\"https://w3c.github.io/aria/#aria-labelledby\"><code>aria-labelledby</code></a> attribute." }} />
      <p dangerouslySetInnerHTML={{ __html: "Authors <em>SHOULD</em> ensure that all dialogs (both modal and non-modal) have at least one <a href=\"#dfn-focusable\">focusable</a> descendant element. Authors <em>SHOULD</em> focus an element in the modal dialog when it is displayed, and authors <em>SHOULD</em> constrain keyboard focus to focusable elements within a modal dialog, until dismissed." }} />
      <p dangerouslySetInnerHTML={{ __html: "Authors <em>SHOULD</em> provide a dialog an accessible description, with the <a href=\"https://w3c.github.io/aria/#aria-describedby\"><code>aria-describedby</code></a> attribute, for instances where authors have set initial keyboard focus on an element that follows content that outlines the purpose of the dialog. Assistive technology <em>SHOULD</em> give precedence to exposing author defined dialog accessible descriptions when a dialog is invoked and user focus is moved to a descendant of the dialog element." }} />
    </>
  ),
  document: (
    <>
      <p dangerouslySetInnerHTML={{ __html: "When <a href=\"https://infra.spec.whatwg.org/#user-agent\">user agent</a> focus moves to an element assigned the role of <code>document</code>, <a href=\"#assistive-technology\">assistive technologies</a> having a reading mode for browsing static content <em>MAY</em> switch to that reading mode and intercept standard input events, such as Up or Down arrow keyboard events, to control the reading cursor." }} />
      <p dangerouslySetInnerHTML={{ __html: "Because <a href=\"#assistive-technology\">assistive technologies</a> that have a reading mode default to that mode for all elements except for those with either a <a href=\"https://w3c.github.io/aria/#widget\"><code>widget</code></a> or <a href=\"https://w3c.github.io/aria/#application\"><code>application</code></a> role, the only circumstance where the <code>document</code> role is useful for changing assistive technology behavior is when the element with role <code>document</code> is a <a href=\"#dfn-focusable\">focusable</a> <a href=\"#dfn-accessibility-child\">accessibility child</a> of a <a href=\"https://w3c.github.io/aria/#widget\"><code>widget</code></a> or <a href=\"https://w3c.github.io/aria/#application\"><code>application</code></a>. For example, given an <a href=\"https://w3c.github.io/aria/#application\"><code>application</code></a> element which contains some static rich text, the author can apply role <code>document</code> to the element containing the text and give it a <code>tabindex</code> of <code>0</code>. When a screen reader user presses the Tab key and places focus on the <code>document</code> element, the user will be able to read the text with the screen reader's reading cursor." }} />
    </>
  ),
  emphasis: (
    <>
      <p>{"See related strong."}</p>
      <p dangerouslySetInnerHTML={{ __html: "The purpose of the <code>emphasis</code> role is to stress or emphasize content. It is not for communicating changes in typographical presentation that do not impact the meaning of the content. Authors <em>SHOULD</em> use the <code>emphasis</code> role only if its absence would change the meaning of the content." }} />
      <p dangerouslySetInnerHTML={{ __html: "The <code>emphasis</code> role is not intended to convey importance; for that purpose, the <a href=\"https://w3c.github.io/aria/#strong\"><code>strong</code></a> role is more appropriate." }} />
    </>
  ),
  feed: (
    <>
      <p dangerouslySetInnerHTML={{ __html: "A <code>feed</code> enables users of <a href=\"#assistive-technology\">assistive technologies</a> that have a document browse mode, such as screen readers, to use the browse mode reading cursor to both read and scroll through a stream of rich content that might continue scrolling infinitely by loading more content as the user reads. In a <code>feed</code>, <a href=\"#assistive-technology\">assistive technologies</a> provide a web application with signals of the user's reading cursor movement by moving <a href=\"https://infra.spec.whatwg.org/#user-agent\">user agent</a> focus, enabling the application to both add new content and visually position content as the user browses the page. The <code>feed</code> also lets authors inform assistive technologies when additions and removals are occurring so assistive technologies can more reliably update their reading view without disrupting reading or degrading performance." }} />
      <p dangerouslySetInnerHTML={{ __html: "For example, a <code>feed</code> could be used to present a stream of news stories where each <a href=\"https://w3c.github.io/aria/#article\"><code>article</code></a> contains a story with text, links, images, and comments as well as widgets for sharing and commenting. As a screen reader user reads and interacts with each story and moves the screen reader reading cursor from story to story, each story scrolls into view and, as needed, new stories are loaded." }} />
      <p dangerouslySetInnerHTML={{ __html: "A <code>feed</code> is a container element whose children have role <a href=\"https://w3c.github.io/aria/#article\"><code>article</code></a>. When <a href=\"https://w3c.github.io/aria/#article\"><code>articles</code></a> are added or removed from either or both ends of a <code>feed</code>, authors <em>SHOULD</em> set <a href=\"https://w3c.github.io/aria/#aria-busy\"><code>aria-busy</code></a> to <code>true</code> on the <code>feed</code> element before the changes are made and set it to <code>false</code> after the changes are complete. Authors <em>SHOULD</em> avoid inserting or removing <a href=\"https://w3c.github.io/aria/#article\"><code>articles</code></a> in the middle of a <code>feed</code>. These requirements help <a href=\"#assistive-technology\">assistive technologies</a> gracefully respond to changes in the <code>feed</code> content that occur simultaneously with user commands to move the reading cursor within the <code>feed</code>." }} />
      <p dangerouslySetInnerHTML={{ __html: "Authors <em>SHOULD</em> make each <a href=\"https://w3c.github.io/aria/#article\"><code>article</code></a> in a <code>feed</code> <a href=\"#dfn-focusable\">focusable</a> and ensure that the application scrolls an <a href=\"https://w3c.github.io/aria/#article\"><code>article</code></a> into view when <a href=\"https://infra.spec.whatwg.org/#user-agent\">user agent</a> focus is set on the <a href=\"https://w3c.github.io/aria/#article\"><code>article</code></a> or one of its descendant elements. For example, in <abbr title=\"Hypertext Markup Language\">HTML</abbr>, each <a href=\"https://w3c.github.io/aria/#article\"><code>article</code></a> element should have a <code>tabindex</code> value of either <code>-1</code> or <code>0</code>." }} />
      <p dangerouslySetInnerHTML={{ __html: "When an <a href=\"#assistive-technology\">assistive technology</a> reading cursor moves from one <a href=\"https://w3c.github.io/aria/#article\"><code>article</code></a> to another, <a href=\"#assistive-technology\">assistive technologies</a> <em>SHOULD</em> set user agent focus on the <a href=\"https://w3c.github.io/aria/#article\"><code>article</code></a> that contains the reading cursor. If the reading cursor lands on a focusable element inside the <a href=\"https://w3c.github.io/aria/#article\"><code>article</code></a>, the assistive technology <em>MAY</em> set focus on that element in lieu of setting focus on the containing <a href=\"https://w3c.github.io/aria/#article\"><code>article</code></a>." }} />
      <p dangerouslySetInnerHTML={{ __html: "Because the ability to scroll to another <a href=\"https://w3c.github.io/aria/#article\"><code>article</code></a> with an <a href=\"#assistive-technology\">assistive technology</a> reading cursor depends on the presence of another <a href=\"https://w3c.github.io/aria/#article\"><code>article</code></a> in the page, authors <em>SHOULD</em> attempt to load additional <a href=\"https://w3c.github.io/aria/#article\"><code>articles</code></a> before <a href=\"https://infra.spec.whatwg.org/#user-agent\">user agent</a> focus reaches an <a href=\"https://w3c.github.io/aria/#article\"><code>article</code></a> at either end of the set of <a href=\"https://w3c.github.io/aria/#article\"><code>articles</code></a> that has been loaded. Alternatively, authors <em>MAY</em> include an <a href=\"https://w3c.github.io/aria/#article\"><code>article</code></a> at either or both ends of the loaded set of <a href=\"https://w3c.github.io/aria/#article\"><code>articles</code></a> that includes an element, such as a <a href=\"https://w3c.github.io/aria/#button\"><code>button</code></a>, that lets the user request more <a href=\"https://w3c.github.io/aria/#article\"><code>articles</code></a> to be loaded." }} />
      <p dangerouslySetInnerHTML={{ __html: "In addition to providing a brief label, authors <em>MAY</em> apply <a href=\"https://w3c.github.io/aria/#aria-describedby\"><code>aria-describedby</code></a> to <a href=\"https://w3c.github.io/aria/#article\"><code>article</code></a> elements in a <code>feed</code> to suggest to screen readers which elements to speak after the label when users navigate by <a href=\"https://w3c.github.io/aria/#article\"><code>article</code></a>. Screen readers <em>MAY</em> provide users with a way to quickly scan <code>feed</code> content by speaking both the label and <a href=\"https://www.w3.org/TR/accname-1.2/#dfn-accessible-description\">accessible description</a> when navigating by <a href=\"https://w3c.github.io/aria/#article\"><code>article</code></a>, enabling the user to ignore repetitive or less important elements, such as embedded interaction widgets, that the author has left out of the description." }} />
      <p dangerouslySetInnerHTML={{ __html: "Authors <em>SHOULD</em> provide keyboard commands for moving focus among <a href=\"https://w3c.github.io/aria/#article\"><code>articles</code></a> in a <code>feed</code> so users who do not utilize an assistive technology that provides <a href=\"https://w3c.github.io/aria/#article\"><code>article</code></a> navigation features can use the keyboard to navigate the <code>feed</code>." }} />
      <p dangerouslySetInnerHTML={{ __html: "If the number of articles available in a <code>feed</code> supply is static, authors <em>MAY</em> specify <a href=\"https://w3c.github.io/aria/#aria-setsize\"><code>aria-setsize</code></a> on <a href=\"https://w3c.github.io/aria/#article\"><code>article</code></a> elements in that <code>feed</code>. However, if the total number is extremely large, indefinite, or changes often, authors <em>MAY</em> set <a href=\"https://w3c.github.io/aria/#aria-setsize\"><code>aria-setsize</code></a> to <code>-1</code> to communicate the unknown size of the set." }} />
      <p dangerouslySetInnerHTML={{ __html: "See the <cite><a href=\"https://www.w3.org/WAI/ARIA/apg/\"><abbr title=\"Accessible Rich Internet Applications\">ARIA</abbr> Authoring Practices Guide</a></cite> for additional details on implementing a feed design pattern." }} />
    </>
  ),
  figure: (
    <>
      <p>{"The parts of a figure MAY be user-navigable."}</p>
      <p dangerouslySetInnerHTML={{ __html: "Authors <em>SHOULD</em> provide a reference to the <code>figure</code> from the main text, but the <code>figure</code> need not be displayed at the same location as the referencing element. Authors <em>MAY</em> provide a <code>figure</code> a <a href=\"https://w3c.github.io/aria/#caption\"><code>caption</code></a> which can include its name, descriptive text, or both. If a <code>caption</code> is provided, and it serves as a description to the contents of the <code>figure</code>, authors <em>SHOULD</em> associate it to the <code>figure</code> element using <a href=\"https://w3c.github.io/aria/#aria-details\"><code>aria-details</code></a>." }} />
      <p dangerouslySetInnerHTML={{ __html: "Authors <em>MAY</em> provide a <code>figure</code> an accessible name using <a href=\"https://w3c.github.io/aria/#aria-label\"><code>aria-label</code></a> or use <a href=\"https://w3c.github.io/aria/#aria-labelledby\"><code>aria-labelledby</code></a> to reference other text in the page to serve as the element's label and accessible name." }} />
      <p dangerouslySetInnerHTML={{ __html: "Please refer to the <a href=\"https://w3c.github.io/aria/#caption\"><code>caption</code></a> role for more information on how to associate a <code>figure</code> with its <code>caption</code>." }} />
      <p dangerouslySetInnerHTML={{ __html: "<a href=\"#assistive-technology\">Assistive technologies</a> <em>SHOULD</em> enable users to quickly navigate to figures. <a href=\"https://infra.spec.whatwg.org/#user-agent\">User agents</a> <em>MAY</em> enable users to quickly navigate to figures." }} />
    </>
  ),
  form: (
    <>
      <p>{"See related search."}</p>
      <p dangerouslySetInnerHTML={{ __html: "A form can contain a mix of host language form controls, scripted controls, and hyperlinks. Authors are reminded to use native host language semantics to create form controls whenever possible. If the purpose of a form is to submit search criteria, authors <em>SHOULD</em> use the <a href=\"https://w3c.github.io/aria/#search\"><code>search</code></a> role instead of the generic <code>form</code> role." }} />
      <p dangerouslySetInnerHTML={{ __html: "Authors <em>SHOULD</em> give each element with role <code>form</code> a brief label that describes the purpose of the form. Authors <em>SHOULD</em> reference a visible label with <a href=\"https://w3c.github.io/aria/#aria-labelledby\"><code>aria-labelledby</code></a> if a visible label is present. Authors <em>SHOULD</em> include the label inside of a heading whenever possible. The heading <em>MAY</em> be an instance of the standard host language heading element or an instance of an element with role <a href=\"https://w3c.github.io/aria/#heading\"><code>heading</code></a>." }} />
      <p dangerouslySetInnerHTML={{ __html: "If an author uses a script to submit a form based on a user action that would otherwise not trigger an <code>onsubmit</code> event (for example, a form submission triggered by the user changing a form element's value), the author <em>SHOULD</em> provide the user with advance notification of the behavior." }} />
      <p dangerouslySetInnerHTML={{ __html: "<a href=\"#assistive-technology\">Assistive technologies</a> <em>SHOULD</em> enable users to quickly navigate to elements with role <code>form</code>. <a href=\"https://infra.spec.whatwg.org/#user-agent\">User agents</a> <em>SHOULD</em> treat elements with role <code>form</code> and an accessible name as navigational <a href=\"#dfn-landmark\">landmarks</a>. <a href=\"https://infra.spec.whatwg.org/#user-agent\">User agents</a> <em>MAY</em> enable users to quickly navigate to elements with role <code>form</code>." }} />
    </>
  ),
  generic: (
    <>
      <p dangerouslySetInnerHTML={{ __html: "The <code>generic</code> role is intended for use as the implicit role of generic elements in host languages (such as <abbr title=\"Hypertext Markup Language\">HTML</abbr> <code>div</code> or <code>span</code>), so is primarily for implementors of user agents. Authors <em>SHOULD NOT</em> use this role in content. Authors <em>MAY</em> use <a href=\"https://w3c.github.io/aria/#presentation\"><code>presentation</code></a> or <a href=\"https://w3c.github.io/aria/#none\"><code>none</code></a> to remove implicit accessibility semantics, or a semantic container role such as <a href=\"https://w3c.github.io/aria/#group\"><code>group</code></a> to semantically group descendants in a named container." }} />
      <p dangerouslySetInnerHTML={{ __html: "Like an element with role <a href=\"https://w3c.github.io/aria/#presentation\"><code>presentation</code></a>, an element with role <code>generic</code> can provide a limited number of accessible states and properties for its descendants, such as <a href=\"https://w3c.github.io/aria/#aria-live\"><code>aria-live</code></a> attributes." }} />
      <p dangerouslySetInnerHTML={{ __html: "However, unlike elements with role <code>presentation</code>, user agents expose <code>generic</code> elements in <a href=\"#dfn-accessibility-api\">accessibility <abbr title=\"Application Programming Interfaces\">APIs</abbr></a> when permitted accessibility attributes have been specified. User agents <em>MAY</em> otherwise ignore <code>generic</code> elements if such permitted attributes have not been specified." }} />
    </>
  ),
  grid: (
    <>
      <p dangerouslySetInnerHTML={{ __html: "The <code>grid</code> role does not imply a specific visual, e.g., tabular, presentation. It describes <a href=\"#dfn-relationship\">relationships</a> among <a href=\"https://dom.spec.whatwg.org/#concept-element\">elements</a>. It can be used for purposes as simple as grouping a collection of checkboxes or navigation links or as complex as creating a full-featured spreadsheet application." }} />
      <p dangerouslySetInnerHTML={{ __html: "The cell elements of a <code>grid</code> have role <a href=\"https://w3c.github.io/aria/#gridcell\"><code>gridcell</code></a>. Authors <em>MAY</em> designate a cell as a row or column header by using either the <a href=\"https://w3c.github.io/aria/#rowheader\"><code>rowheader</code></a> or <a href=\"https://w3c.github.io/aria/#columnheader\"><code>columnheader</code></a> <a href=\"#dfn-role\">role</a> in lieu of the <a href=\"https://w3c.github.io/aria/#gridcell\"><code>gridcell</code></a> role. Authors <em>MUST</em> ensure elements with role <a href=\"https://w3c.github.io/aria/#gridcell\"><code>gridcell</code></a>, <a href=\"https://w3c.github.io/aria/#columnheader\"><code>columnheader</code></a>, or <a href=\"https://w3c.github.io/aria/#rowheader\"><code>rowheader</code></a> are <a href=\"#dfn-accessibility-child\">accessibility children</a> of elements with role <a href=\"https://w3c.github.io/aria/#row\"><code>row</code></a>, which are in turn are <a href=\"#dfn-accessibility-child\">accessibility children</a> of an element with role <a href=\"https://w3c.github.io/aria/#rowgroup\"><code>rowgroup</code></a>, or <code>grid</code>." }} />
      <p dangerouslySetInnerHTML={{ __html: "To be <a href=\"#dfn-keyboard-accessible\">keyboard accessible</a>, authors <em>SHOULD</em> manage focus of descendants of a <code>grid</code> as described in <a href=\"#managingfocus\">Managing Focus</a>. When a user is navigating the <code>grid</code> content with a keyboard, authors <em>SHOULD</em> set focus as follows:" }} />
      <p dangerouslySetInnerHTML={{ __html: "Authors <em>SHOULD</em> provide a mechanism for changing to an interaction or edit mode that allows users to navigate and interact with content contained inside a focusable cell if that focusable cell contains any of the following:" }} />
      <p dangerouslySetInnerHTML={{ __html: "For example, if a cell in a spreadsheet contains a <a href=\"https://w3c.github.io/aria/#combobox\"><code>combobox</code></a> or editable text, the <kbd>Enter</kbd> key might be used to activate a cell interaction or editing mode when that cell has focus so the directional arrow keys can be used to operate the contained <a href=\"https://w3c.github.io/aria/#combobox\"><code>combobox</code></a> or <a href=\"https://w3c.github.io/aria/#textbox\"><code>textbox</code></a>. Depending on the implementation, pressing <kbd>Enter</kbd> again, <kbd>Tab</kbd>, <kbd>Escape</kbd>, or another key might switch the application back to the grid navigation mode." }} />
      <p dangerouslySetInnerHTML={{ __html: "Authors <em>MAY</em> use a <a href=\"https://w3c.github.io/aria/#gridcell\"><code>gridcell</code></a> to display the result of a formula, which could be editable by the user. In a spreadsheet application, for example, a <a href=\"https://w3c.github.io/aria/#gridcell\"><code>gridcell</code></a> might show a value calculated from a formula until the user activates the <a href=\"https://w3c.github.io/aria/#gridcell\"><code>gridcell</code></a> for editing when a <a href=\"https://w3c.github.io/aria/#textbox\"><code>textbox</code></a> appears in the <a href=\"https://w3c.github.io/aria/#gridcell\"><code>gridcell</code></a> containing the formula in an editable state." }} />
      <p dangerouslySetInnerHTML={{ __html: "If <a href=\"https://w3c.github.io/aria/#aria-readonly\"><code>aria-readonly</code></a> is set on an element with role <code>grid</code>, <a href=\"https://infra.spec.whatwg.org/#user-agent\">user agents</a> <em>MUST</em> propagate the value to all <a href=\"https://w3c.github.io/aria/#gridcell\"><code>gridcell</code></a> elements that are <a href=\"#dfn-accessibility-descendant\">accessibility descendants</a> of that <code>grid</code> and expose the value in the accessibility <abbr title=\"Application Programming Interface\">API</abbr>. An author <em>MAY</em> override the propagated value of <a href=\"https://w3c.github.io/aria/#aria-readonly\"><code>aria-readonly</code></a> for an individual <a href=\"https://w3c.github.io/aria/#gridcell\"><code>gridcell</code></a> element." }} />
      <p dangerouslySetInnerHTML={{ __html: "In a <code>grid</code> that provides cell content editing functions, if the content of a focusable <a href=\"https://w3c.github.io/aria/#gridcell\"><code>gridcell</code></a> element is not editable, authors <em>MAY</em> set <a href=\"https://w3c.github.io/aria/#aria-readonly\"><code>aria-readonly</code></a> to <code>true</code> on the <code>gridcell</code> element. However, the value of <a href=\"https://w3c.github.io/aria/#aria-readonly\"><code>aria-readonly</code></a>, whether specified for a <code>grid</code> or individual cells, only indicates whether the content contained in cells is editable. It does not represent availability of functions for navigating or manipulating the <code>grid</code> itself." }} />
      <p dangerouslySetInnerHTML={{ __html: "An unspecified value for <a href=\"https://w3c.github.io/aria/#aria-readonly\"><code>aria-readonly</code></a> does not imply that a <code>grid</code> or a <a href=\"https://w3c.github.io/aria/#gridcell\"><code>gridcell</code></a> contains editable content. For example, if a <code>grid</code> presents a collection of elements that are not editable, such as a collection of <a href=\"https://w3c.github.io/aria/#link\"><code>link</code></a> elements representing dates in a datepicker, it is not necessary for the author to specify a value for <a href=\"https://w3c.github.io/aria/#aria-readonly\"><code>aria-readonly</code></a>." }} />
      <p dangerouslySetInnerHTML={{ __html: "Authors <em>MAY</em> indicate that a focusable <a href=\"https://w3c.github.io/aria/#gridcell\"><code>gridcell</code></a> is selectable as the object of an action with the <a href=\"https://w3c.github.io/aria/#aria-selected\"><code>aria-selected</code></a> attribute. If the <code>grid</code> allows multiple <a href=\"https://w3c.github.io/aria/#gridcell\"><code>gridcell</code></a>s to be selected, the author <em>SHOULD</em> set <a href=\"https://w3c.github.io/aria/#aria-multiselectable\"><code>aria-multiselectable</code></a> to <code>true</code> on the element with role <code>grid</code>." }} />
      <p dangerouslySetInnerHTML={{ __html: "Since <abbr title=\"Accessible Rich Internet Applications\">WAI-ARIA</abbr> can augment an element of the host language, a <code>grid</code> can reuse the elements and attributes of a native table, such as an <abbr title=\"Hypertext Markup Language\">HTML</abbr> <code>table</code> element. For example, if an author applies the <code>grid</code> role to an <abbr title=\"Hypertext Markup Language\">HTML</abbr> <code>table</code> element, the author does not need to apply the <a href=\"https://w3c.github.io/aria/#row\"><code>row</code></a> and <a href=\"https://w3c.github.io/aria/#gridcell\"><code>gridcell</code></a> roles to the descendant <abbr title=\"Hypertext Markup Language\">HTML</abbr> <code>tr</code> and <code>td</code> elements because the <a href=\"https://infra.spec.whatwg.org/#user-agent\">user agent</a> will automatically make the appropriate translations. When the author is reusing a native host language table element and needs a <a href=\"https://w3c.github.io/aria/#gridcell\"><code>gridcell</code></a> element to span multiple rows or columns, the author <em>SHOULD</em> apply the appropriate host language attributes instead of <abbr title=\"Accessible Rich Internet Applications\">WAI-ARIA</abbr> <a href=\"https://w3c.github.io/aria/#aria-rowspan\"><code>aria-rowspan</code></a> or <a href=\"https://w3c.github.io/aria/#aria-colspan\"><code>aria-colspan</code></a> properties." }} />
      <p dangerouslySetInnerHTML={{ __html: "Authors <em>SHOULD</em> provide an accessible name for a <code>grid</code>, which can be done with the <a href=\"https://w3c.github.io/aria/#aria-label\"><code>aria-label</code></a> or <a href=\"https://w3c.github.io/aria/#aria-labelledby\"><code>aria-labelledby</code></a> attribute. Authors <em>SHOULD</em> reference a visible label with <a href=\"https://w3c.github.io/aria/#aria-labelledby\"><code>aria-labelledby</code></a> if a visible label is present for the <code>grid</code>." }} />
      <p dangerouslySetInnerHTML={{ __html: "See the <cite><a href=\"https://www.w3.org/WAI/ARIA/apg/\"><abbr title=\"Accessible Rich Internet Applications\">ARIA</abbr> Authoring Practices Guide</a></cite> for additional details on implementing grid design patterns." }} />
    </>
  ),
  gridcell: (
    <>
      <p dangerouslySetInnerHTML={{ __html: "A <code>gridcell</code> can be <a href=\"#dfn-focusable\">focusable</a>, editable, and selectable. A <code>gridcell</code> can have <a href=\"#dfn-relationship\">relationships</a> such as <a href=\"https://w3c.github.io/aria/#aria-controls\"><code>aria-controls</code></a> to address the application of functional relationships." }} />
      <p dangerouslySetInnerHTML={{ __html: "If an author intends a <code>gridcell</code> to have a row header, column header, or both, and if the relevant headers cannot be determined from the <abbr title=\"Document Object Model\">DOM</abbr> structure, authors <em>SHOULD</em> explicitly indicate which header cells are relevant to the <code>gridcell</code> by applying <a href=\"https://w3c.github.io/aria/#aria-describedby\"><code>aria-describedby</code></a> on the <code>gridcell</code> and referencing <a href=\"https://dom.spec.whatwg.org/#concept-element\">elements</a> with <a href=\"#dfn-role\">role</a> <a href=\"https://w3c.github.io/aria/#rowheader\"><code>rowheader</code></a> or <a href=\"https://w3c.github.io/aria/#columnheader\"><code>columnheader</code></a>." }} />
      <p dangerouslySetInnerHTML={{ __html: "In a <a href=\"https://w3c.github.io/aria/#treegrid\"><code>treegrid</code></a>, authors <em>MAY</em> define a <code>gridcell</code> as expandable by using the <a href=\"https://w3c.github.io/aria/#aria-expanded\"><code>aria-expanded</code></a> attribute. If the <a href=\"https://w3c.github.io/aria/#aria-expanded\"><code>aria-expanded</code></a> attribute is provided, it applies only to the individual cell. It is not a proxy for the container <a href=\"https://w3c.github.io/aria/#row\"><code>row</code></a>, which also can be expanded. The main use case for providing this attribute on a <code>gridcell</code> is pivot table behavior." }} />
      <p dangerouslySetInnerHTML={{ __html: "Authors <em>MUST</em> ensure <a href=\"https://dom.spec.whatwg.org/#concept-element\">elements</a> with <a href=\"#dfn-role\">role</a> gridcell are <a href=\"#dfn-accessibility-child\">accessibility children</a> of an element with the <a href=\"#dfn-role\">role</a> <a href=\"https://w3c.github.io/aria/#row\"><code>row</code></a>." }} />
    </>
  ),
  group: (
    <>
      <p dangerouslySetInnerHTML={{ __html: "Contrast with <a href=\"https://w3c.github.io/aria/#region\"><code>region</code></a>, which is a grouping of user interface objects that will be included in a page summary or table of contents." }} />
      <p dangerouslySetInnerHTML={{ __html: "Authors <em>SHOULD</em> use a <code>group</code> to form a logical collection of items in a <a href=\"#dfn-widget\">widget</a>, such as children in a tree widget forming a collection of siblings in a hierarchy. However, when a <code>group</code> is used in the context of a <a href=\"https://w3c.github.io/aria/#listbox\"><code>listbox</code></a>, for example, authors <em>MUST</em> limit its children to <a href=\"https://w3c.github.io/aria/#option\"><code>option</code></a> elements. Therefore, proper handling of <code>group</code> by authors and assistive technologies is determined by the context in which it is provided." }} />
      <p dangerouslySetInnerHTML={{ __html: "Authors <em>MAY</em> nest <code>group</code> elements. If a section is significant enough to warrant inclusion in the web page's table of contents, the author <em>SHOULD</em> assign it a <a href=\"#dfn-role\">role</a> of <a href=\"https://w3c.github.io/aria/#region\"><code>region</code></a> or a <a href=\"#landmark_roles\">standard landmark role</a>." }} />
    </>
  ),
  heading: (
    <>
      <p dangerouslySetInnerHTML={{ __html: "To ensure elements with a role of <code>heading</code> are organized into a logical outline, authors <em>MUST</em> use the <a href=\"https://w3c.github.io/aria/#aria-level\"><code>aria-level</code></a> attribute to indicate the proper nesting level." }} />
    </>
  ),
  img: (
    <>
      <p>{"See synonym img."}</p>
      <p dangerouslySetInnerHTML={{ __html: "An <code>img</code> can contain captions and descriptive text, as well as multiple image files that when viewed together give the impression of a single image. An <code>img</code> represents a single graphic within a document, whether or not it is formed by a collection of drawing <a href=\"#dfn-object\">objects</a>. In order for an element with a <a href=\"#dfn-role\">role</a> of <code>img</code> to be <a href=\"#dfn-perceivable\">perceivable</a>, authors <em>MUST</em> provide the element with an <a href=\"https://www.w3.org/TR/accname-1.2/#dfn-accessible-name\">accessible name</a>. This can be done using the <a href=\"https://w3c.github.io/aria/#aria-label\"><code>aria-label</code></a> or <a href=\"https://w3c.github.io/aria/#aria-labelledby\"><code>aria-labelledby</code></a> attribute." }} />
    </>
  ),
  insertion: (
    <>
      <p>{"See related deletion."}</p>
      <p dangerouslySetInnerHTML={{ __html: "Insertions are typically used to either mark differences between two versions of content or to designate content suggested for addition in scenarios where multiple people are revising content." }} />
    </>
  ),
  link: (
    <>
      <p>{"See related button."}</p>
      <p dangerouslySetInnerHTML={{ __html: "If this is a native link in the host language (such as an <abbr title=\"Hypertext Markup Language\">HTML</abbr> anchor with an <code>href</code> value), activating the link causes the <a href=\"https://infra.spec.whatwg.org/#user-agent\">user agent</a> to navigate to that resource. If this is a simulated link, the author is responsible for managing navigation." }} />
    </>
  ),
  list: (
    <>
      <p>{"See related listbox."}</p>
      <p dangerouslySetInnerHTML={{ __html: "Lists contain children whose <a href=\"#dfn-role\">role</a> is <a href=\"https://w3c.github.io/aria/#listitem\"><code>listitem</code></a>." }} />
    </>
  ),
  listbox: (
    <>
      <p>{"See related combobox and list."}</p>
      <p dangerouslySetInnerHTML={{ __html: "Items within the list are static and, unlike standard <abbr title=\"Hypertext Markup Language\">HTML</abbr> <code>select</code> <a href=\"https://dom.spec.whatwg.org/#concept-element\">elements</a>, can contain images. List boxes contain children whose <a href=\"#dfn-role\">role</a> is <a href=\"https://w3c.github.io/aria/#option\"><code>option</code></a> or elements whose <a href=\"#dfn-role\">role</a> is <a href=\"https://w3c.github.io/aria/#group\"><code>group</code></a> which in turn contain children whose <a href=\"#dfn-role\">role</a> is <a href=\"https://w3c.github.io/aria/#option\"><code>option</code></a>." }} />
      <p dangerouslySetInnerHTML={{ __html: "To be <a href=\"#dfn-keyboard-accessible\">keyboard accessible</a>, authors <em>SHOULD</em> manage focus of <a href=\"https://w3c.github.io/aria/#option\"><code>option</code></a> descendants for all instances of this <a href=\"#dfn-role\">role</a>, as described in <a href=\"#managingfocus\">Managing Focus</a>." }} />
      <p dangerouslySetInnerHTML={{ __html: "Elements with the role <code>listbox</code> have an implicit <a href=\"https://w3c.github.io/aria/#aria-orientation\"><code>aria-orientation</code></a> value of <code>vertical</code>." }} />
    </>
  ),
  listitem: (
    <>
      <p dangerouslySetInnerHTML={{ __html: "Authors <em>MUST</em> ensure <a href=\"https://dom.spec.whatwg.org/#concept-element\">elements</a> whose <a href=\"#dfn-role\">role</a> is <code>listitem</code> are <a href=\"#dfn-accessibility-child\">accessibility children</a> of an <a href=\"https://dom.spec.whatwg.org/#concept-element\">element</a> whose <a href=\"#dfn-role\">role</a> is <a href=\"https://w3c.github.io/aria/#list\"><code>list</code></a>." }} />
    </>
  ),
  log: (
    <>
      <p dangerouslySetInnerHTML={{ __html: "Examples include chat logs, messaging history, game log, or an error log. In contrast to other live regions, in this <a href=\"#dfn-role\">role</a> there is a <a href=\"#dfn-relationship\">relationship</a> between the arrival of new items in the log and the reading order. The log contains a meaningful sequence and new information is added only to the end of the log, not at arbitrary points." }} />
      <p dangerouslySetInnerHTML={{ __html: "Elements with the role <code>log</code> have an implicit <a href=\"https://w3c.github.io/aria/#aria-live\"><code>aria-live</code></a> value of <code>polite</code>." }} />
    </>
  ),
  main: (
    <>
      <p dangerouslySetInnerHTML={{ __html: "This marks the content that is directly related to or expands upon the central topic of the document. The <code>main</code> <a href=\"#dfn-role\">role</a> is a non-obtrusive alternative for \"skip to main content\" links, where the navigation option to go to the main content (or other <a href=\"#dfn-landmark\">landmarks</a>) is provided by <a href=\"#assistive-technology\">assistive technologies</a>, or by a <a href=\"https://infra.spec.whatwg.org/#user-agent\">user agent</a> or browser extension, through a keyboard shortcut or <abbr title=\"User Interface\">UI</abbr> feature such as a side panel or dialog." }} />
      <p dangerouslySetInnerHTML={{ __html: "<a href=\"#assistive-technology\">Assistive technologies</a> <em>SHOULD</em> enable users to quickly navigate to elements with role <code>main</code>. <a href=\"https://infra.spec.whatwg.org/#user-agent\">user agents</a> <em>SHOULD</em> treat elements with role <code>main</code> as navigational <a href=\"#dfn-landmark\">landmarks</a>. <a href=\"https://infra.spec.whatwg.org/#user-agent\">user agents</a> <em>MAY</em> enable users to quickly navigate to elements with role <code>main</code>." }} />
      <p dangerouslySetInnerHTML={{ __html: "The author <em>SHOULD</em> mark no more than one <a href=\"https://dom.spec.whatwg.org/#concept-element\">element</a> on a page with the <code>main</code> role." }} />
    </>
  ),
  marquee: (
    <>
      <p dangerouslySetInnerHTML={{ __html: "Common usages of <code>marquee</code> include stock tickers and ad banners." }} />
    </>
  ),
  math: (
    <>
      <p dangerouslySetInnerHTML={{ __html: "Content with the role <code>math</code> is intended to be marked up in an accessible format such as <cite><a href=\"https://www.w3.org/TR/MathML3/\"><abbr title=\"Mathematical Markup Language\">MathML</abbr></a></cite> [<cite><a href=\"#bib-mathml3\" title=\"Mathematical Markup Language (MathML) Version 3.0 2nd Edition\">MathML3</a></cite>], or with another type of textual representation such as TeX or LaTeX, which can be converted to an accessible format by native browser implementations or a polyfill library." }} />
      <p dangerouslySetInnerHTML={{ __html: "While it is not ideal to use an image of a mathematical expression, there exists a significant amount of legacy content where images are used to represent mathematical expressions. Authors <em>SHOULD</em> ensure that images of math are labeled by text that describes the mathematical expression as it might be spoken." }} />
    </>
  ),
  menu: (
    <>
      <p dangerouslySetInnerHTML={{ __html: "A menu is a container, generally rendered as a popup or overlay, for a set of menu items that can be invoked to perform an action or function. The function is almost always closely related or directly related to the element that the user activated to invoke the menu. Activating a menu item both performs the associated function of the menu item, and results in the automatic dismissal of the menu." }} />
      <p dangerouslySetInnerHTML={{ __html: "The <code>menu</code> <a href=\"#dfn-role\">role</a> is appropriate when a set of menu items is presented in a manner similar to a popup menu. For instance, a menu could be used to represent a context menu for its invoking element, or it would be used to render sub-menus for items of a <a href=\"https://w3c.github.io/aria/#menubar\"><code>menubar</code></a> or another <code>menu</code> popup." }} />
      <p dangerouslySetInnerHTML={{ __html: "To be <a href=\"#dfn-keyboard-accessible\">keyboard accessible</a>, authors <em>SHOULD</em> manage focus of descendants for all instances of this <a href=\"#dfn-role\">role</a>, as described in <a href=\"#managingfocus\">Managing Focus</a>." }} />
      <p dangerouslySetInnerHTML={{ __html: "Elements with the role <code>menu</code> have an implicit <a href=\"https://w3c.github.io/aria/#aria-orientation\"><code>aria-orientation</code></a> value of <code>vertical</code>." }} />
    </>
  ),
  menubar: (
    <>
      <p dangerouslySetInnerHTML={{ __html: "The <code>menubar</code> <a href=\"#dfn-role\">role</a> is used to create a menu bar similar to those found in Windows, Mac, and Gnome desktop applications. A menu bar is used to create a consistent set of frequently used commands. Authors <em>SHOULD</em> ensure that <code>menubar</code> interaction is similar to the typical menu bar interaction in a desktop graphical user interface." }} />
      <p dangerouslySetInnerHTML={{ __html: "To be <a href=\"#dfn-keyboard-accessible\">keyboard accessible</a>, authors <em>SHOULD</em> manage focus of descendants for all instances of this <a href=\"#dfn-role\">role</a>, as described in <a href=\"#managingfocus\">Managing Focus</a>." }} />
      <p dangerouslySetInnerHTML={{ __html: "Elements with the role <code>menubar</code> have an implicit <a href=\"https://w3c.github.io/aria/#aria-orientation\"><code>aria-orientation</code></a> value of <code>horizontal</code>." }} />
    </>
  ),
  menuitem: (
    <>
      <p dangerouslySetInnerHTML={{ __html: "Authors <em>MUST</em> ensure <a href=\"https://dom.spec.whatwg.org/#concept-element\">elements</a> with <a href=\"#dfn-role\">role</a> <code>menuitem</code> are <a href=\"#dfn-accessibility-child\">accessibility children</a> of an element with role <a href=\"https://w3c.github.io/aria/#menu\"><code>menu</code></a>, <a href=\"https://w3c.github.io/aria/#menubar\"><code>menubar</code></a>, or an element with role <a href=\"https://w3c.github.io/aria/#group\"><code>group</code></a> that is an <a href=\"#dfn-accessibility-child\">accessibility child</a> of an element with role <a href=\"https://w3c.github.io/aria/#menu\"><code>menu</code></a> or <a href=\"https://w3c.github.io/aria/#menubar\"><code>menubar</code></a>." }} />
      <p dangerouslySetInnerHTML={{ __html: "Authors <em>MAY</em> disable a menu item with the <a href=\"https://w3c.github.io/aria/#aria-disabled\"><code>aria-disabled</code></a> attribute. If the menu item has its <a href=\"https://w3c.github.io/aria/#aria-haspopup\"><code>aria-haspopup</code></a> attribute set to <code>true</code>, it indicates that the menu item can be used to launch a sub-level menu, and authors <em>SHOULD</em> display a new sub-level menu when the menu item is activated." }} />
      <p dangerouslySetInnerHTML={{ __html: "In order to identify that they are related <a href=\"#dfn-widget\">widgets</a>, authors <em>MUST</em> ensure that menu items are <a href=\"#dfn-accessibility-descendant\">accessibility descendants</a> of an element with role <a href=\"https://w3c.github.io/aria/#menu\"><code>menu</code></a> or <a href=\"https://w3c.github.io/aria/#menubar\"><code>menubar</code></a>. Authors <em>MAY</em> separate menu items into sets by use of a <a href=\"https://w3c.github.io/aria/#separator\"><code>separator</code></a> or an element with an equivalent role from the native markup language." }} />
    </>
  ),
  menuitemcheckbox: (
    <>
      <p dangerouslySetInnerHTML={{ __html: "Authors <em>MUST</em> ensure <a href=\"https://dom.spec.whatwg.org/#concept-element\">elements</a> with <a href=\"#dfn-role\">role</a> <code>menuitemcheckbox</code> are <a href=\"#dfn-accessibility-child\">accessibility children</a> of an element with role <a href=\"https://w3c.github.io/aria/#menu\"><code>menu</code></a>, <a href=\"https://w3c.github.io/aria/#menubar\"><code>menubar</code></a>, or an element with role <a href=\"https://w3c.github.io/aria/#group\"><code>group</code></a> that is an <a href=\"#dfn-accessibility-child\">accessibility child</a> of an element with role <a href=\"https://w3c.github.io/aria/#menu\"><code>menu</code></a> or <a href=\"https://w3c.github.io/aria/#menubar\"><code>menubar</code></a>." }} />
      <p dangerouslySetInnerHTML={{ __html: "The <a href=\"https://w3c.github.io/aria/#aria-checked\"><code>aria-checked</code></a> <a href=\"https://dom.spec.whatwg.org/#concept-attribute\">attribute</a> of a <code>menuitemcheckbox</code> indicates whether the menu item is checked (<code>true</code>), unchecked (<code>false</code>), or represents a sub-level menu of other menu items that have a mixture of checked and unchecked values (<code>mixed</code>)." }} />
      <p dangerouslySetInnerHTML={{ __html: "In order to identify that they are related <a href=\"#dfn-widget\">widgets</a>, authors <em>MUST</em> ensure that menu item checkboxes are the <a href=\"#dfn-accessibility-descendant\">accessibility descendants</a> of an element with role <a href=\"https://w3c.github.io/aria/#menu\"><code>menu</code></a> or <a href=\"https://w3c.github.io/aria/#menubar\"><code>menubar</code></a>. Authors <em>MAY</em> separate menu items into sets by use of a <a href=\"https://w3c.github.io/aria/#separator\"><code>separator</code></a> or an element with an equivalent role from the native markup language." }} />
    </>
  ),
  menuitemradio: (
    <>
      <p dangerouslySetInnerHTML={{ __html: "Authors <em>MUST</em> ensure <a href=\"https://dom.spec.whatwg.org/#concept-element\">elements</a> with <a href=\"#dfn-role\">role</a> <code>menuitemradio</code> are <a href=\"#dfn-accessibility-child\">accessibility children</a> of an element with role <a href=\"https://w3c.github.io/aria/#menu\"><code>menu</code></a>, <a href=\"https://w3c.github.io/aria/#menubar\"><code>menubar</code></a>, or an element with role <a href=\"https://w3c.github.io/aria/#group\"><code>group</code></a> that is an <a href=\"#dfn-accessibility-child\">accessibility child</a> of an element with role <a href=\"https://w3c.github.io/aria/#menu\"><code>menu</code></a> or <a href=\"https://w3c.github.io/aria/#menubar\"><code>menubar</code></a>." }} />
      <p dangerouslySetInnerHTML={{ __html: "Authors <em>SHOULD</em> enforce that only one <code>menuitemradio</code> in a group can be checked at the same time. When one item in the group is checked, the previously checked item becomes unchecked (its <a href=\"https://w3c.github.io/aria/#aria-checked\"><code>aria-checked</code></a> <a href=\"https://dom.spec.whatwg.org/#concept-attribute\">attribute</a> becomes <code>false</code>)." }} />
      <p dangerouslySetInnerHTML={{ __html: "In order to identify that they are related <a href=\"#dfn-widget\">widgets</a>, authors <em>MUST</em> ensure that menu item radios are <a href=\"#dfn-accessibility-descendant\">accessibility descendants</a> of an element with role <a href=\"https://w3c.github.io/aria/#menu\"><code>menu</code></a> or <a href=\"https://w3c.github.io/aria/#menubar\"><code>menubar</code></a>." }} />
      <p dangerouslySetInnerHTML={{ __html: "If a <a href=\"https://w3c.github.io/aria/#menu\"><code>menu</code></a> or <a href=\"https://w3c.github.io/aria/#menubar\"><code>menubar</code></a> contains more than one group of <code>menuitemradio</code> elements, or if the menu contains one group and other, unrelated menu items, authors <em>SHOULD</em> contain each set of related <code>menuitemradio</code> elements in an element using the <a href=\"https://w3c.github.io/aria/#group\"><code>group</code></a> role. Authors <em>MAY</em> also delimit the group from other menu items with an element using the <a href=\"https://w3c.github.io/aria/#separator\"><code>separator</code></a> role, or an element with an equivalent role from the native markup language." }} />
    </>
  ),
  meter: (
    <>
      <p>{"See related progressbar."}</p>
      <p dangerouslySetInnerHTML={{ __html: "Authors <em>MAY</em> set <a href=\"https://w3c.github.io/aria/#aria-valuemin\"><code>aria-valuemin</code></a> and <a href=\"https://w3c.github.io/aria/#aria-valuemax\"><code>aria-valuemax</code></a> to indicate the minimum and maximum values for the <code>meter</code>. Otherwise, their implicit values follow the same rules as <code>&lt;input type=\"<code><a href=\"https://html.spec.whatwg.org/multipage/input.html#attr-input-type-range-keyword\">range</a></code>\"&gt;</code> in <abbr title=\"Hypertext Markup Language\">HTML</abbr>:" }} />
      <p dangerouslySetInnerHTML={{ __html: "The value of <a href=\"https://w3c.github.io/aria/#aria-valuenow\"><code>aria-valuenow</code></a> <em>MUST NOT</em> fall below or exceed the computed values of <code>aria-valuemin</code> and <code>aria-valuemax</code>, respectively." }} />
      <p dangerouslySetInnerHTML={{ __html: "Authors <em>SHOULD NOT</em> use the <code>meter</code> role to indicate progress; the <a href=\"https://w3c.github.io/aria/#progressbar\"><code>progressbar</code></a> role exists to address that need." }} />
    </>
  ),
  navigation: (
    <>
      <p dangerouslySetInnerHTML={{ __html: "<a href=\"#assistive-technology\">Assistive technologies</a> <em>SHOULD</em> enable users to quickly navigate to elements with role <code>navigation</code>. <a href=\"https://infra.spec.whatwg.org/#user-agent\">user agents</a> <em>SHOULD</em> treat elements with role <code>navigation</code> as navigational <a href=\"#dfn-landmark\">landmarks</a>. <a href=\"https://infra.spec.whatwg.org/#user-agent\">user agents</a> <em>MAY</em> enable users to quickly navigate to elements with role <code>navigation</code>." }} />
    </>
  ),
  none: (
    <>
      <p>{"See synonym presentation."}</p>
    </>
  ),
  note: (
    <>
      <p dangerouslySetInnerHTML={{ __html: "A <code>note</code> is content provided by the author of the page or document, it is not to be used for providing reactions or suggestions. For these purposes, please review <a href=\"https://w3c.github.io/aria/#comment\"><code>comment</code></a> and <a href=\"https://w3c.github.io/aria/#suggestion\"><code>suggestion</code></a>." }} />
      <p dangerouslySetInnerHTML={{ __html: "When used within the normal flow of a page's content, a <code>note</code> has an implicit association with the content that it supplements. The following example demonstrates using a <code>note</code> to call out additional information in the natural reading order of a page:" }} />
    </>
  ),
  option: (
    <>
      <p dangerouslySetInnerHTML={{ __html: "Authors <em>MUST</em> ensure <a href=\"https://dom.spec.whatwg.org/#concept-element\">elements</a> with <a href=\"#dfn-role\">role</a> <code>option</code> are <a href=\"#dfn-accessibility-child\">accessibility children</a> of an element with <a href=\"#dfn-role\">role</a> <a href=\"https://w3c.github.io/aria/#listbox\"><code>listbox</code></a> or of an element with <a href=\"#dfn-role\">role</a> <a href=\"https://w3c.github.io/aria/#group\"><code>group</code></a> that is the <a href=\"#dfn-accessibility-child\">accessibility child</a> of an element with <a href=\"#dfn-role\">role</a> <code>listbox</code>. Options not associated with a <a href=\"https://w3c.github.io/aria/#listbox\"><code>listbox</code></a> might not be correctly mapped to an <a href=\"#dfn-accessibility-api\">accessibility <abbr title=\"Application Programming Interface\">API</abbr></a>." }} />
      <p dangerouslySetInnerHTML={{ __html: "In certain conditions, a user agent <em>MAY</em> provide an implicit value for <a href=\"https://w3c.github.io/aria/#aria-selected\"><code>aria-selected</code></a> for each <a href=\"https://w3c.github.io/aria/#option\"><code>option</code></a> in a <a href=\"https://w3c.github.io/aria/#listbox\"><code>listbox</code></a>, and if it does, the user agent <em>MUST</em> ensure the following conditions are met before providing an implicit value:" }} />
      <p dangerouslySetInnerHTML={{ __html: "If a user agent provides an implicit <a href=\"https://w3c.github.io/aria/#aria-selected\"><code>aria-selected</code></a> value for an <a href=\"https://w3c.github.io/aria/#option\"><code>option</code></a>, the value <em>SHOULD</em> be <code>true</code> if the <a href=\"https://w3c.github.io/aria/#option\"><code>option</code></a> has <abbr title=\"Document Object Model\">DOM</abbr> focus or the <a href=\"https://w3c.github.io/aria/#listbox\"><code>listbox</code></a> has <abbr title=\"Document Object Model\">DOM</abbr> focus and the <a href=\"https://w3c.github.io/aria/#option\"><code>option</code></a> is referenced by <a href=\"https://w3c.github.io/aria/#aria-activedescendant\"><code>aria-activedescendant</code></a>. Otherwise, if a user agent provides an implicit <a href=\"https://w3c.github.io/aria/#aria-selected\"><code>aria-selected</code></a> value for an <a href=\"https://w3c.github.io/aria/#option\"><code>option</code></a>, the value <em>SHOULD</em> be <code>false</code>." }} />
      <p dangerouslySetInnerHTML={{ __html: "Authors <em>SHOULD</em> indicate selection for <a href=\"https://w3c.github.io/aria/#option\"><code>option</code></a> elements using one of the following:" }} />
      <p dangerouslySetInnerHTML={{ __html: "Authors <em>SHOULD NOT</em> specify both <a href=\"https://w3c.github.io/aria/#aria-selected\"><code>aria-selected</code></a> and <a href=\"https://w3c.github.io/aria/#aria-checked\"><code>aria-checked</code></a> on <a href=\"https://w3c.github.io/aria/#option\"><code>option</code></a> elements contained by the same <a href=\"https://w3c.github.io/aria/#listbox\"><code>listbox</code></a> except in the extremely rare circumstances where all the following conditions are met:" }} />
    </>
  ),
  presentation: (
    <>
      <p>{"See synonym none."}</p>
    </>
  ),
  progressbar: (
    <>
      <p dangerouslySetInnerHTML={{ __html: "A progressbar indicates that the user's request has been received and the application is making progress toward completing the requested action." }} />
      <p dangerouslySetInnerHTML={{ __html: "Authors <em>MAY</em> set <a href=\"https://w3c.github.io/aria/#aria-valuemin\"><code>aria-valuemin</code></a> and <a href=\"https://w3c.github.io/aria/#aria-valuemax\"><code>aria-valuemax</code></a> to indicate the minimum and maximum progress indicator values. Otherwise, their implicit values follow the same rules as <code>&lt;input type=\"<code><a href=\"https://html.spec.whatwg.org/multipage/input.html#attr-input-type-range-keyword\">range</a></code>\"&gt;</code> in <abbr title=\"Hypertext Markup Language\">HTML</abbr>:" }} />
      <p dangerouslySetInnerHTML={{ __html: "The author <em>SHOULD</em> supply a <span>value</span> for <a href=\"https://w3c.github.io/aria/#aria-valuenow\"><code>aria-valuenow</code></a> unless the value is indeterminate, in which case the author <em>SHOULD</em> omit the <a href=\"https://w3c.github.io/aria/#aria-valuenow\"><code>aria-valuenow</code></a> attribute. Authors <em>SHOULD</em> update this value when the visual progress indicator is updated. If the <code>progressbar</code> is describing the loading progress of a particular region of a page, authors <em>SHOULD</em> both use <a href=\"https://w3c.github.io/aria/#aria-describedby\"><code>aria-describedby</code></a> to reference the progressbar status, and set the <a href=\"https://w3c.github.io/aria/#aria-busy\"><code>aria-busy</code></a> attribute to <code>true</code> on the region until it is finished loading. It is not possible for the user to alter the value of a <code>progressbar</code> because it is always read-only." }} />
    </>
  ),
  radio: (
    <>
      <p dangerouslySetInnerHTML={{ __html: "Authors <em>SHOULD</em> ensure that <a href=\"https://dom.spec.whatwg.org/#concept-element\">elements</a> with role <code>radio</code> are explicitly grouped in order to indicate which ones affect the same value. This is achieved by enclosing the radio elements in an element with role <a href=\"https://w3c.github.io/aria/#radiogroup\"><code>radiogroup</code></a>. If it is not possible to make the radio buttons <abbr title=\"Document Object Model\">DOM</abbr> children of the <a href=\"https://w3c.github.io/aria/#radiogroup\"><code>radiogroup</code></a>, authors <em>SHOULD</em> use the <a href=\"https://w3c.github.io/aria/#aria-owns\"><code>aria-owns</code></a> <a href=\"https://dom.spec.whatwg.org/#concept-attribute\">attribute</a> on the <a href=\"https://w3c.github.io/aria/#radiogroup\"><code>radiogroup</code></a> element to indicate the <a href=\"#dfn-relationship\">relationship</a> to its children." }} />
    </>
  ),
  radiogroup: (
    <>
      <p dangerouslySetInnerHTML={{ __html: "A <code>radiogroup</code> is a type of <a href=\"https://w3c.github.io/aria/#select\"><code>select</code></a> list that can only have a single entry checked at any one time. Authors <em>SHOULD</em> enforce that only one radio button in a group can be checked at the same time. When one item in the group is checked, the previously checked item becomes unchecked (its <a href=\"https://w3c.github.io/aria/#aria-checked\"><code>aria-checked</code></a> <a href=\"https://dom.spec.whatwg.org/#concept-attribute\">attribute</a> becomes <code>false</code>)." }} />
      <p dangerouslySetInnerHTML={{ __html: "Authors <em>SHOULD</em> provide an accessible name for a <code>radiogroup</code>, which can be done with the <a href=\"https://w3c.github.io/aria/#aria-label\"><code>aria-label</code></a> or <a href=\"https://w3c.github.io/aria/#aria-labelledby\"><code>aria-labelledby</code></a> attribute. Authors <em>SHOULD</em> reference a visible label with <a href=\"https://w3c.github.io/aria/#aria-labelledby\"><code>aria-labelledby</code></a> if a visible label is present for the <code>radiogroup</code>." }} />
    </>
  ),
  region: (
    <>
      <p>{"Such a page summary could be generated dynamically by a user agent or assistive technology."}</p>
      <p dangerouslySetInnerHTML={{ __html: "Authors <em>SHOULD</em> limit use of the region role to sections containing content with a purpose that is not accurately described by one of the other <a href=\"#landmark_roles\">landmark roles</a>, such as <a href=\"https://w3c.github.io/aria/#main\"><code>main</code></a>, <a href=\"https://w3c.github.io/aria/#complementary\"><code>complementary</code></a>, or <a href=\"https://w3c.github.io/aria/#navigation\"><code>navigation</code></a>." }} />
      <p dangerouslySetInnerHTML={{ __html: "Authors <em>MUST</em> give each element with role region a brief label that describes the purpose of the content in the region. Authors <em>SHOULD</em> reference a visible label with <a href=\"https://w3c.github.io/aria/#aria-labelledby\"><code>aria-labelledby</code></a> if a visible label is present. Authors <em>SHOULD</em> include the label inside of a heading whenever possible. The heading <em>MAY</em> be an instance of the standard host language heading element or an instance of an element with role <a href=\"https://w3c.github.io/aria/#heading\"><code>heading</code></a>." }} />
      <p dangerouslySetInnerHTML={{ __html: "<a href=\"#assistive-technology\">Assistive technologies</a> <em>SHOULD</em> enable users to quickly navigate to elements with role <code>region</code>. <a href=\"https://infra.spec.whatwg.org/#user-agent\">User agents</a> <em>SHOULD</em> treat elements with role <code>region</code> and an accessible name as navigational <a href=\"#dfn-landmark\">landmarks</a>. <a href=\"https://infra.spec.whatwg.org/#user-agent\">User agents</a> <em>MAY</em> enable users to quickly navigate to elements with role <code>region</code>." }} />
    </>
  ),
  row: (
    <>
      <p dangerouslySetInnerHTML={{ __html: "Rows contain <a href=\"https://w3c.github.io/aria/#cell\"><code>cell</code></a> or <a href=\"https://w3c.github.io/aria/#gridcell\"><code>gridcell</code></a> <a href=\"https://dom.spec.whatwg.org/#concept-element\">elements</a>, and thus serve to organize a <a href=\"https://w3c.github.io/aria/#table\"><code>table</code></a>, <a href=\"https://w3c.github.io/aria/#grid\"><code>grid</code></a>, or <a href=\"https://w3c.github.io/aria/#treegrid\"><code>treegrid</code></a>." }} />
      <p dangerouslySetInnerHTML={{ __html: "While the row role can be used in a <a href=\"https://w3c.github.io/aria/#table\"><code>table</code></a>, <a href=\"https://w3c.github.io/aria/#grid\"><code>grid</code></a>, or <a href=\"https://w3c.github.io/aria/#treegrid\"><code>treegrid</code></a>, the semantics of <a href=\"https://w3c.github.io/aria/#aria-expanded\"><code>aria-expanded</code></a>, <a href=\"https://w3c.github.io/aria/#aria-posinset\"><code>aria-posinset</code></a>, <a href=\"https://w3c.github.io/aria/#aria-setsize\"><code>aria-setsize</code></a>, and <a href=\"https://w3c.github.io/aria/#aria-level\"><code>aria-level</code></a> are only applicable to the hierarchical structure of an interactive tree grid. Therefore, authors <em>MUST NOT</em> apply <a href=\"https://w3c.github.io/aria/#aria-expanded\"><code>aria-expanded</code></a>, <a href=\"https://w3c.github.io/aria/#aria-posinset\"><code>aria-posinset</code></a>, <a href=\"https://w3c.github.io/aria/#aria-setsize\"><code>aria-setsize</code></a>, and <a href=\"https://w3c.github.io/aria/#aria-level\"><code>aria-level</code></a> to a <a href=\"https://w3c.github.io/aria/#row\"><code>row</code></a> that descends from a <a href=\"https://w3c.github.io/aria/#table\"><code>table</code></a> or <a href=\"https://w3c.github.io/aria/#grid\"><code>grid</code></a>, and user agents <em>SHOULD NOT</em> expose any of these four properties to assistive technologies unless the <a href=\"https://w3c.github.io/aria/#row\"><code>row</code></a> descends from a <a href=\"https://w3c.github.io/aria/#treegrid\"><code>treegrid</code></a>." }} />
      <p dangerouslySetInnerHTML={{ __html: "Authors <em>MUST</em> ensure <a href=\"https://dom.spec.whatwg.org/#concept-element\">elements</a> with <a href=\"#dfn-role\">role</a> <code>row</code> are <a href=\"#dfn-accessibility-child\">accessibility children</a> of an element with the role <a href=\"https://w3c.github.io/aria/#table\"><code>table</code></a>, <a href=\"https://w3c.github.io/aria/#grid\"><code>grid</code></a>, <a href=\"https://w3c.github.io/aria/#rowgroup\"><code>rowgroup</code></a>, or <a href=\"https://w3c.github.io/aria/#treegrid\"><code>treegrid</code></a>." }} />
    </>
  ),
  rowgroup: (
    <>
      <p dangerouslySetInnerHTML={{ __html: "The <code>rowgroup</code> role establishes a <a href=\"#dfn-relationship\">relationship</a> with its <a href=\"#dfn-accessibility-child\">accessibility children</a> of role <a href=\"https://w3c.github.io/aria/#row\"><code>row</code></a>. It is a structural equivalent to the <code>thead</code>, <code>tfoot</code>, and <code>tbody</code> elements in an <abbr title=\"Hypertext Markup Language\">HTML</abbr> <code>table</code> <a href=\"https://dom.spec.whatwg.org/#concept-element\">element</a>." }} />
      <p dangerouslySetInnerHTML={{ __html: "Authors <em>MUST</em> ensure <a href=\"https://dom.spec.whatwg.org/#concept-element\">elements</a> with <a href=\"#dfn-role\">role</a> <code>rowgroup</code> are <a href=\"#dfn-accessibility-child\">accessibility children</a> of an element with the role <a href=\"https://w3c.github.io/aria/#grid\"><code>grid</code></a>, <a href=\"https://w3c.github.io/aria/#table\"><code>table</code></a>, or <a href=\"https://w3c.github.io/aria/#treegrid\"><code>treegrid</code></a>." }} />
    </>
  ),
  rowheader: (
    <>
      <p dangerouslySetInnerHTML={{ __html: "The <a href=\"https://w3c.github.io/aria/#rowheader\"><code>rowheader</code></a> role can be used to identify a cell as a header for a row in a <a href=\"https://w3c.github.io/aria/#table\"><code>table</code></a>, <a href=\"https://w3c.github.io/aria/#grid\"><code>grid</code></a>, or <a href=\"https://w3c.github.io/aria/#treegrid\"><code>treegrid</code></a>. The rowheader establishes a <a href=\"#dfn-relationship\">relationship</a> between it and all cells in the corresponding row. It is a structural equivalent to setting <code>scope=\"row\"</code> on an <abbr title=\"Hypertext Markup Language\">HTML</abbr> <code>th</code> <a href=\"https://dom.spec.whatwg.org/#concept-element\">element</a>." }} />
      <p dangerouslySetInnerHTML={{ __html: "Authors <em>MUST</em> ensure <a href=\"https://dom.spec.whatwg.org/#concept-element\">elements</a> with <a href=\"#dfn-role\">role</a> <code>rowheader</code> are <a href=\"#dfn-accessibility-child\">accessibility children</a> of an element with the role <a href=\"https://w3c.github.io/aria/#row\"><code>row</code></a>." }} />
      <p dangerouslySetInnerHTML={{ __html: "Applying the <a href=\"https://w3c.github.io/aria/#aria-selected\"><code>aria-selected</code></a> state on a rowheader <em>MUST NOT</em> cause the user agent to automatically propagate the <a href=\"https://w3c.github.io/aria/#aria-selected\"><code>aria-selected</code></a> state to all the cells in the corresponding row. An author <em>MAY</em> choose to propagate selection in this manner depending on the specific application." }} />
      <p dangerouslySetInnerHTML={{ __html: "While the <code>rowheader</code> role can be used in both interactive grids and non-interactive tables, the use of <a href=\"https://w3c.github.io/aria/#aria-expanded\"><code>aria-expanded</code></a>, <a href=\"https://w3c.github.io/aria/#aria-readonly\"><code>aria-readonly</code></a>, and <a href=\"https://w3c.github.io/aria/#aria-required\"><code>aria-required</code></a> is only applicable to interactive elements. Therefore, authors <em>SHOULD NOT</em> use <a href=\"https://w3c.github.io/aria/#aria-expanded\"><code>aria-expanded</code></a>, <a href=\"https://w3c.github.io/aria/#aria-readonly\"><code>aria-readonly</code></a>, or <a href=\"https://w3c.github.io/aria/#aria-required\"><code>aria-required</code></a> in a <code>rowheader</code> that descends from a <a href=\"https://w3c.github.io/aria/#table\"><code>table</code></a>, and user agents <em>SHOULD NOT</em> expose these properties to <a href=\"#assistive-technology\">assistive technologies</a> unless the <code>rowheader</code> descends from a <a href=\"https://w3c.github.io/aria/#grid\"><code>grid</code></a> or <a href=\"https://w3c.github.io/aria/#treegrid\"><code>treegrid</code></a>." }} />
    </>
  ),
  scrollbar: (
    <>
      <p dangerouslySetInnerHTML={{ __html: "A scrollbar represents the current value and range of possible values via the size of the scrollbar and position of the thumb with respect to the visible range of the orientation (horizontal or vertical) it controls. Its orientation represents the orientation of the scrollbar and the scrolling effect on the viewing area controlled by the scrollbar. It is typically possible to add to or subtract from the current value by using directional keys such as arrow keys." }} />
      <p dangerouslySetInnerHTML={{ __html: "Authors <em>MAY</em> set the <a href=\"https://w3c.github.io/aria/#aria-controls\"><code>aria-controls</code></a> attribute on the scrollbar element to reference the scrollable area it controls." }} />
      <p dangerouslySetInnerHTML={{ __html: "Authors <em>MAY</em> set <a href=\"https://w3c.github.io/aria/#aria-valuemin\"><code>aria-valuemin</code></a> and <a href=\"https://w3c.github.io/aria/#aria-valuemax\"><code>aria-valuemax</code></a> to indicate the minimum and maximum thumb position. Otherwise, their implicit values follow the same rules as <code>&lt;input type=\"<code><a href=\"https://html.spec.whatwg.org/multipage/input.html#attr-input-type-range-keyword\">range</a></code>\"&gt;</code> in <abbr title=\"Hypertext Markup Language\">HTML</abbr>:" }} />
      <p dangerouslySetInnerHTML={{ __html: "Authors <em>MUST</em> set the <a href=\"https://w3c.github.io/aria/#aria-valuenow\"><code>aria-valuenow</code></a> attribute to indicate the current thumb position. If aria-valuenow is missing or has an unexpected value, <a href=\"https://infra.spec.whatwg.org/#user-agent\">user agents</a> <em>MAY</em> implement the repair techniques specified in the <a href=\"#authorErrorDefaultValuesTable\">section describing handling author errors in states and properties</a>, which are equivalent to the repair techniques for <code>&lt;input type=\"<code><a href=\"https://html.spec.whatwg.org/multipage/input.html#attr-input-type-range-keyword\">range</a></code>\"&gt;</code> in <abbr title=\"Hypertext Markup Language\">HTML</abbr>." }} />
      <p dangerouslySetInnerHTML={{ __html: "Elements with the role <code>scrollbar</code> have an implicit <a href=\"https://w3c.github.io/aria/#aria-orientation\"><code>aria-orientation</code></a> value of <code>vertical</code>." }} />
    </>
  ),
  search: (
    <>
      <p>{"See related form and searchbox."}</p>
      <p dangerouslySetInnerHTML={{ __html: "A search region can be a mix of host language form controls, scripted controls, and hyperlinks." }} />
      <p dangerouslySetInnerHTML={{ __html: "<a href=\"#assistive-technology\">Assistive technologies</a> <em>SHOULD</em> enable users to quickly navigate to elements with role <code>search</code>. <a href=\"https://infra.spec.whatwg.org/#user-agent\">user agents</a> <em>SHOULD</em> treat elements with role <code>search</code> as navigational <a href=\"#dfn-landmark\">landmarks</a>. <a href=\"https://infra.spec.whatwg.org/#user-agent\">user agents</a> <em>MAY</em> enable users to quickly navigate to elements with role <code>search</code>." }} />
    </>
  ),
  searchbox: (
    <>
      <p>{"See related textbox and search."}</p>
    </>
  ),
  section: (
    <>
      <p dangerouslySetInnerHTML={{ __html: "<code>section</code> is an <a href=\"#isAbstract\">abstract role</a> used for the ontology. Authors <em>MUST NOT</em> use <code>section</code> role in content." }} />
    </>
  ),
  separator: (
    <>
      <p dangerouslySetInnerHTML={{ __html: "There are two types of separators: a static <a href=\"https://w3c.github.io/aria/#structure\"><code>structure</code></a> that provides only a visible boundary and a <a href=\"#dfn-focusable\">focusable</a>, interactive <a href=\"https://w3c.github.io/aria/#widget\"><code>widget</code></a> that is also moveable. If a <code>separator</code> is not focusable, it is revealed to <a href=\"#assistive-technology\">assistive technologies</a> as a static structural element. For example, a static <code>separator</code> can be used to help visually divide two groups of menu items in a menu or to provide a horizontal rule between two sections of a page." }} />
      <p dangerouslySetInnerHTML={{ __html: "Authors <em>MAY</em> make a <code>separator</code> focusable to create a <a href=\"https://w3c.github.io/aria/#widget\"><code>widget</code></a> that both provides a visible boundary between two sections of content and enables the user to change the relative size of the sections by changing the position of the <code>separator</code>. A variable <code>separator</code> widget can be moved continuously within a range, whereas a fixed <code>separator</code> widget supports only two discrete positions. Typically, a fixed <code>separator</code> widget is used to toggle one of the sections between expanded and collapsed states." }} />
      <p dangerouslySetInnerHTML={{ __html: "If the <code>separator</code> is focusable, authors <em>MUST</em> set the value of <a href=\"https://w3c.github.io/aria/#aria-valuenow\"><code>aria-valuenow</code></a> to a <a href=\"#valuetype_number\">number</a> reflecting the current position of the <code>separator</code> and update that value when it changes. Authors <em>SHOULD</em> also provide the value of <a href=\"https://w3c.github.io/aria/#aria-valuemin\"><code>aria-valuemin</code></a> if it is not <code>0</code> and the value of <a href=\"https://w3c.github.io/aria/#aria-valuemax\"><code>aria-valuemax</code></a> if it is not <code>100</code>. If missing or not a number, the implicit values of these attributes are as follows:" }} />
      <p dangerouslySetInnerHTML={{ __html: "In applications where there is more than one focusable <code>separator</code>, authors <em>SHOULD</em> provide an accessible name for each one." }} />
      <p dangerouslySetInnerHTML={{ __html: "Elements with the role <code>separator</code> have an implicit <a href=\"https://w3c.github.io/aria/#aria-orientation\"><code>aria-orientation</code></a> value of <code>horizontal</code>." }} />
    </>
  ),
  slider: (
    <>
      <p dangerouslySetInnerHTML={{ __html: "A slider represents the current value and range of possible values via the size of the slider and position of the thumb. It is typically possible to add to or subtract from the current value by using directional keys such as arrow keys." }} />
      <p dangerouslySetInnerHTML={{ __html: "Authors <em>MAY</em> set the <a href=\"https://w3c.github.io/aria/#aria-valuemin\"><code>aria-valuemin</code></a> and <a href=\"https://w3c.github.io/aria/#aria-valuemax\"><code>aria-valuemax</code></a> attributes. Otherwise, their implicit values follow the same rules as <code>&lt;input type=\"<code><a href=\"https://html.spec.whatwg.org/multipage/input.html#attr-input-type-range-keyword\">range</a></code>\"&gt;</code> in <abbr title=\"Hypertext Markup Language\">HTML</abbr>:" }} />
      <p dangerouslySetInnerHTML={{ __html: "Authors <em>MUST</em> set the <a href=\"https://w3c.github.io/aria/#aria-valuenow\"><code>aria-valuenow</code></a> attribute. If aria-valuenow is missing or has an unexpected value, browsers <em>MAY</em> implement the repair techniques specified in the <a href=\"#authorErrorDefaultValuesTable\">section describing handling author errors in states and properties</a>, which are equivalent to the repair techniques for <code>&lt;input type=\"<code><a href=\"https://html.spec.whatwg.org/multipage/input.html#attr-input-type-range-keyword\">range</a></code>\"&gt;</code> in <abbr title=\"Hypertext Markup Language\">HTML</abbr>." }} />
      <p dangerouslySetInnerHTML={{ __html: "Elements with the role <code>slider</code> have an implicit <a href=\"https://w3c.github.io/aria/#aria-orientation\"><code>aria-orientation</code></a> value of <code>horizontal</code>." }} />
    </>
  ),
  spinbutton: (
    <>
      <p dangerouslySetInnerHTML={{ __html: "A <code>spinbutton</code> typically allows users to change its displayed value by activating increment and decrement buttons that step through a set of allowed values. Some implementations display the value in an text field that allows editing and typing but typically limits input in ways that help prevent invalid values." }} />
      <p dangerouslySetInnerHTML={{ __html: "Although a <code>spinbutton</code> is similar in appearance to many presentations of <code>select</code>, it is advisable to use <code>spinbutton</code> when working with known ranges (especially in the case of large ranges) as opposed to distinct options. For example, a <code>spinbutton</code> representing a range from 1 to 1,000,000 would provide much better performance than a <code>select</code> <a href=\"#dfn-widget\">widget</a> representing the same values." }} />
      <p dangerouslySetInnerHTML={{ __html: "Authors <em>MAY</em> create a <code>spinbutton</code> with <a href=\"#dfn-accessibility-child\">accessibility children</a>, but <em>MUST</em> limit those elements to a <a href=\"https://w3c.github.io/aria/#textbox\"><code>textbox</code></a> and/or two <a href=\"https://w3c.github.io/aria/#button\"><code>buttons</code></a>. Alternatively, authors <em>MAY</em> apply the <a href=\"https://w3c.github.io/aria/#spinbutton\"><code>spinbutton</code></a> role to a text input and create sibling buttons to support the increment and decrement functions." }} />
      <p dangerouslySetInnerHTML={{ __html: "To be <a href=\"#dfn-keyboard-accessible\">keyboard accessible</a>, authors <em>SHOULD</em> manage focus of descendants for all instances of this <a href=\"#dfn-role\">role</a>, as described in <a href=\"#managingfocus\">Managing Focus</a>. When a <code>spinbutton</code> receives focus, authors <em>SHOULD</em> ensure focus is placed on the <a href=\"https://w3c.github.io/aria/#textbox\"><code>textbox</code></a> element if one is present, and on the <code>spinbutton</code> itself otherwise. Authors <em>SHOULD</em> also ensure the <kbd>up</kbd> and <kbd>down</kbd> arrows on a keyboard perform the increment and decrement functions and that the increment and decrement <a href=\"https://w3c.github.io/aria/#button\"><code>button</code></a> elements are <em>NOT</em> included in the primary navigation ring, e.g., the Tab ring in <abbr title=\"Hypertext Markup Language\">HTML</abbr>." }} />
      <p dangerouslySetInnerHTML={{ __html: "Authors <em>SHOULD</em> set the <a href=\"https://w3c.github.io/aria/#aria-valuenow\"><code>aria-valuenow</code></a> attribute when the <a href=\"https://w3c.github.io/aria/#spinbutton\"><code>spinbutton</code></a> has a value. Authors <em>SHOULD</em> set the <a href=\"https://w3c.github.io/aria/#aria-valuemin\"><code>aria-valuemin</code></a> attribute when there is a minimum value, and the <a href=\"https://w3c.github.io/aria/#aria-valuemax\"><code>aria-valuemax</code></a> attribute when there is a maximum value." }} />
    </>
  ),
  status: (
    <>
      <p dangerouslySetInnerHTML={{ __html: "Authors <em>SHOULD</em> ensure an element with role <code>status</code> does not receive focus as a result of change in status." }} />
      <p dangerouslySetInnerHTML={{ __html: "Status is a form of <a href=\"#dfn-live-region\">live region</a>. If another part of the page controls what appears in the status, authors <em>SHOULD</em> make the <a href=\"#dfn-relationship\">relationship</a> explicit with the <a href=\"https://w3c.github.io/aria/#aria-controls\"><code>aria-controls</code></a> <a href=\"https://dom.spec.whatwg.org/#concept-attribute\">attribute</a>." }} />
      <p dangerouslySetInnerHTML={{ __html: "<a href=\"#assistive-technology\">Assistive technologies</a> <em>MAY</em> reserve some cells of a Braille display to render the status." }} />
      <p dangerouslySetInnerHTML={{ __html: "Elements with the role <code>status</code> have an implicit <a href=\"https://w3c.github.io/aria/#aria-live\"><code>aria-live</code></a> value of <code>polite</code> and an implicit <a href=\"https://w3c.github.io/aria/#aria-atomic\"><code>aria-atomic</code></a> value of <code>true</code>." }} />
    </>
  ),
  strong: (
    <>
      <p>{"See related emphasis."}</p>
      <p dangerouslySetInnerHTML={{ __html: "The purpose of the <code>strong</code> role is to communicate strong importance, seriousness, or urgency. It is not for communicating changes in typographical presentation that are not important to the meaning of the content. Authors <em>SHOULD</em> use the <code>strong</code> role only if its absence would change the meaning of the content." }} />
      <p dangerouslySetInnerHTML={{ __html: "The <code>strong</code> role is not intended to convey stress or emphasis; for that purpose, the <a href=\"https://w3c.github.io/aria/#emphasis\"><code>emphasis</code></a> role is more appropriate." }} />
    </>
  ),
  subscript: (
    <>
      <p>{"See related superscript."}</p>
      <p dangerouslySetInnerHTML={{ __html: "The <code>subscript</code> role is intended to be used only to mark up typographical conventions that have specific meanings; not for typographical presentation for presentation's sake. In general, authors <em>SHOULD</em> use this role only if the absence of the subscript would change the meaning of the content." }} />
    </>
  ),
  superscript: (
    <>
      <p>{"See related subscript."}</p>
      <p dangerouslySetInnerHTML={{ __html: "The <code>superscript</code> role is intended to be used only to mark up typographical conventions that have specific meanings; not for typographical presentation for presentation's sake. In general, authors <em>SHOULD</em> use this role only if the absence of the superscript would change the meaning of the content." }} />
    </>
  ),
  switch: (
    <>
      <p>{"See related checkbox."}</p>
      <p dangerouslySetInnerHTML={{ __html: "The <a href=\"https://w3c.github.io/aria/#aria-checked\"><code>aria-checked</code></a> <a href=\"https://dom.spec.whatwg.org/#concept-attribute\">attribute</a> of a <code>switch</code> indicates whether the input is on (<code>true</code>) or off (<code>false</code>). The <code>mixed</code> value is invalid, and user agents <em>MUST</em> treat a <code>mixed</code> value as equivalent to <code>false</code> for this role." }} />
    </>
  ),
  tab: (
    <>
      <p dangerouslySetInnerHTML={{ __html: "If a <a href=\"https://w3c.github.io/aria/#tabpanel\"><code>tabpanel</code></a> or item in a <a href=\"https://w3c.github.io/aria/#tabpanel\"><code>tabpanel</code></a> has focus, the associated <code>tab</code> is the currently active tab in the <a href=\"https://w3c.github.io/aria/#tablist\"><code>tablist</code></a>, as defined in <a href=\"#managingfocus\">Managing Focus</a>. <a href=\"https://w3c.github.io/aria/#tablist\"><code>tablist</code></a> elements, which contain a set of associated <a href=\"https://w3c.github.io/aria/#tab\"><code>tab</code></a> elements, are typically placed near a series of <a href=\"https://w3c.github.io/aria/#tabpanel\"><code>tabpanel</code></a> elements, usually preceding it. See the <cite><a href=\"https://www.w3.org/WAI/ARIA/apg/\"><abbr title=\"Accessible Rich Internet Applications\">ARIA</abbr> Authoring Practices Guide</a></cite> for details on implementing a tab set design pattern." }} />
      <p dangerouslySetInnerHTML={{ __html: "Authors <em>MUST</em> ensure <a href=\"https://dom.spec.whatwg.org/#concept-element\">elements</a> with <a href=\"#dfn-role\">role</a> <a href=\"https://w3c.github.io/aria/#tab\"><code>tab</code></a> are <a href=\"#dfn-accessibility-child\">accessibility children</a> of an element with the role <a href=\"https://w3c.github.io/aria/#tablist\"><code>tablist</code></a>." }} />
      <p dangerouslySetInnerHTML={{ __html: "Authors <em>MUST</em> ensure that if a <code>tab</code> is active, a corresponding <code>tabpanel</code> that represents the active <code>tab</code> is rendered." }} />
      <p dangerouslySetInnerHTML={{ __html: "Authors <em>SHOULD</em> associate a <code>tabpanel</code> <a href=\"https://dom.spec.whatwg.org/#concept-element\">element</a> with its <a href=\"https://w3c.github.io/aria/#tab\"><code>tab</code></a>, by using the <a href=\"https://w3c.github.io/aria/#aria-controls\"><code>aria-controls</code></a> attribute on the tab to reference the tab panel, and/or by using the <a href=\"https://w3c.github.io/aria/#aria-labelledby\"><code>aria-labelledby</code></a> attribute on the tab panel to reference the tab." }} />
      <p dangerouslySetInnerHTML={{ __html: "Authors <em>SHOULD</em> ensure the <a href=\"https://w3c.github.io/aria/#tabpanel\"><code>tabpanel</code></a> associated with the currently active tab is <a href=\"#dfn-perceivable\">perceivable</a> to the user." }} />
      <p dangerouslySetInnerHTML={{ __html: "For a single-selectable <a href=\"https://w3c.github.io/aria/#tablist\"><code>tablist</code></a>, authors <em>SHOULD</em> <a href=\"#dfn-hide-from-all-users\">hide from all users</a> other <code>tabpanel</code> <a href=\"https://dom.spec.whatwg.org/#concept-element\">elements</a> until the user selects the tab associated with that tabpanel. For a multi-selectable <a href=\"https://w3c.github.io/aria/#tablist\"><code>tablist</code></a>, authors <em>SHOULD</em> ensure that the <a href=\"https://w3c.github.io/aria/#tab\"><code>tab</code></a> for each visible <a href=\"https://w3c.github.io/aria/#tabpanel\"><code>tabpanel</code></a> has the <a href=\"https://w3c.github.io/aria/#aria-expanded\"><code>aria-expanded</code></a> <a href=\"https://dom.spec.whatwg.org/#concept-attribute\">attribute</a> set to <code>true</code>, and that the <code>tabs</code> associated with the remaining <a href=\"#dfn-hide-from-all-users\">hidden from all users</a> <code>tabpanel</code> elements have their <a href=\"https://w3c.github.io/aria/#aria-expanded\"><code>aria-expanded</code></a> attributes set to <code>false</code>." }} />
      <p dangerouslySetInnerHTML={{ __html: "Authors <em>SHOULD</em> ensure that a selected tab has its <a href=\"https://w3c.github.io/aria/#aria-selected\"><code>aria-selected</code></a> attribute set to <code>true</code>, that inactive tab elements have their <a href=\"https://w3c.github.io/aria/#aria-selected\"><code>aria-selected</code></a> attribute set to <code>false</code>, and that the currently selected tab provides a visual indication that it is selected." }} />
      <p dangerouslySetInnerHTML={{ __html: "In certain conditions, a user agent <em>MAY</em> provide an implicit value for <a href=\"https://w3c.github.io/aria/#aria-selected\"><code>aria-selected</code></a> for each <a href=\"https://w3c.github.io/aria/#tab\"><code>tab</code></a> in a <a href=\"https://w3c.github.io/aria/#tablist\"><code>tablist</code></a>, and if it does, the user agent <em>MUST</em> ensure the following conditions are met before providing an implicit value:" }} />
    </>
  ),
  table: (
    <>
      <p>{"See related grid."}</p>
      <p dangerouslySetInnerHTML={{ __html: "The <code>table</code> role is intended for tabular containers which are not interactive. If the tabular container maintains a selection state, provides its own two-dimensional navigation, or allows the user to rearrange or otherwise manipulate its contents or the display thereof, authors <em>SHOULD</em> use <a href=\"https://w3c.github.io/aria/#grid\"><code>grid</code></a> or <a href=\"https://w3c.github.io/aria/#treegrid\"><code>treegrid</code></a> instead." }} />
      <p dangerouslySetInnerHTML={{ __html: "Authors <em>SHOULD</em> provide an accessible name for a <code>table</code>, which can be done with the <a href=\"https://w3c.github.io/aria/#aria-label\"><code>aria-label</code></a> or <a href=\"https://w3c.github.io/aria/#aria-labelledby\"><code>aria-labelledby</code></a> attribute. Authors <em>SHOULD</em> reference a visible label with <a href=\"https://w3c.github.io/aria/#aria-labelledby\"><code>aria-labelledby</code></a> if a visible label is present for the <code>table</code>." }} />
      <p dangerouslySetInnerHTML={{ __html: "Authors <em>SHOULD</em> prefer the use of the host language's semantics for table whenever possible, such as the <code>&lt;<code><a href=\"https://html.spec.whatwg.org/multipage/tables.html#the-table-element\">table</a></code>&gt;</code> element in <abbr title=\"Hypertext Markup Language\">HTML</abbr>." }} />
    </>
  ),
  tablist: (
    <>
      <p dangerouslySetInnerHTML={{ __html: "To be <a href=\"#dfn-keyboard-accessible\">keyboard accessible</a>, authors <em>SHOULD</em> manage focus of descendants for all instances of this <a href=\"#dfn-role\">role</a>, as described in <a href=\"#managingfocus\">Managing Focus</a>." }} />
      <p dangerouslySetInnerHTML={{ __html: "For a single-selectable <a href=\"https://w3c.github.io/aria/#tablist\"><code>tablist</code></a>, authors <em>SHOULD</em> <a href=\"#dfn-hide-from-all-users\">hide from all users</a> other <code>tabpanel</code> <a href=\"https://dom.spec.whatwg.org/#concept-element\">elements</a> until the user selects the tab associated with that tabpanel. For a multi-selectable <a href=\"https://w3c.github.io/aria/#tablist\"><code>tablist</code></a>, authors <em>SHOULD</em> ensure that the <a href=\"https://w3c.github.io/aria/#tab\"><code>tab</code></a> for each visible <a href=\"https://w3c.github.io/aria/#tabpanel\"><code>tabpanel</code></a> has the <a href=\"https://w3c.github.io/aria/#aria-expanded\"><code>aria-expanded</code></a> <a href=\"https://dom.spec.whatwg.org/#concept-attribute\">attribute</a> set to <code>true</code>, and that the <code>tabs</code> associated with the remaining <a href=\"#dfn-hide-from-all-users\">hidden from all users</a> <code>tabpanel</code> elements have their <a href=\"https://w3c.github.io/aria/#aria-expanded\"><code>aria-expanded</code></a> attributes set to <code>false</code>." }} />
      <p dangerouslySetInnerHTML={{ __html: "<a href=\"https://w3c.github.io/aria/#tablist\"><code>tablist</code></a> elements are typically placed near, and usually preceding, a series of <a href=\"https://w3c.github.io/aria/#tabpanel\"><code>tabpanel</code></a> elements. See the <cite><a href=\"https://www.w3.org/WAI/ARIA/apg/\"><abbr title=\"Accessible Rich Internet Applications\">ARIA</abbr> Authoring Practices Guide</a></cite> for details on implementing a tab set design pattern." }} />
      <p dangerouslySetInnerHTML={{ __html: "Elements with the role <a href=\"https://w3c.github.io/aria/#tablist\"><code>tablist</code></a> have an implicit <a href=\"https://w3c.github.io/aria/#aria-orientation\"><code>aria-orientation</code></a> value of <code>horizontal</code>." }} />
    </>
  ),
  tabpanel: (
    <>
      <p dangerouslySetInnerHTML={{ __html: "Authors <em>MUST</em> ensure that if a <code>tab</code> is active, a corresponding <code>tabpanel</code> that represents the active <code>tab</code> is rendered." }} />
      <p dangerouslySetInnerHTML={{ __html: "Authors <em>SHOULD</em> associate a <code>tabpanel</code> <a href=\"https://dom.spec.whatwg.org/#concept-element\">element</a> with its <a href=\"https://w3c.github.io/aria/#tab\"><code>tab</code></a>, by using the <a href=\"https://w3c.github.io/aria/#aria-controls\"><code>aria-controls</code></a> attribute on the tab to reference the tab panel, and/or by using the <a href=\"https://w3c.github.io/aria/#aria-labelledby\"><code>aria-labelledby</code></a> attribute on the tab panel to reference the tab." }} />
      <p dangerouslySetInnerHTML={{ __html: "<a href=\"https://w3c.github.io/aria/#tablist\"><code>tablist</code></a> elements are typically placed near, and usually preceding, a series of <a href=\"https://w3c.github.io/aria/#tabpanel\"><code>tabpanel</code></a> elements. See the <cite><a href=\"https://www.w3.org/WAI/ARIA/apg/\"><abbr title=\"Accessible Rich Internet Applications\">ARIA</abbr> Authoring Practices Guide</a></cite> for details on implementing a tab set design pattern." }} />
    </>
  ),
  term: (
    <>
      <p>{"See related definition."}</p>
      <p dangerouslySetInnerHTML={{ __html: "The <code>term</code> role is used to explicitly identify a word or phrase for which a <a href=\"https://w3c.github.io/aria/#definition\"><code>definition</code></a> has been provided by the author or is expected to be provided by the user. If there is an existing <a href=\"https://w3c.github.io/aria/#definition\"><code>definition</code></a>, or a form or form control to enter a definition, authors <em>SHOULD</em> set <a href=\"https://w3c.github.io/aria/#aria-details\"><code>aria-details</code></a> to point to the related element." }} />
      <p dangerouslySetInnerHTML={{ __html: "Authors <em>SHOULD NOT</em> use the <code>term</code> role on interactive elements such as links because doing so could prevent users of <a href=\"#assistive-technology\">assistive technologies</a> from interacting with those elements." }} />
    </>
  ),
  textbox: (
    <>
      <p dangerouslySetInnerHTML={{ __html: "If the <a href=\"https://w3c.github.io/aria/#aria-multiline\"><code>aria-multiline</code></a> <a href=\"https://dom.spec.whatwg.org/#concept-attribute\">attribute</a> is <code>true</code>, the <a href=\"#dfn-widget\">widget</a> accepts line breaks within the input, as in an <abbr title=\"Hypertext Markup Language\">HTML</abbr> <code>textarea</code>. Otherwise, this is a simple text box. The intended use is for languages that do not have a text input <a href=\"https://dom.spec.whatwg.org/#concept-element\">element</a>, or cases in which an element with different <a href=\"#dfn-semantics\">semantics</a> is repurposed as a text field." }} />
      <p dangerouslySetInnerHTML={{ __html: "Authors <em>MUST</em> limit the children of a textbox to non-interactive, entirely presentational elements such as icons used to visually convey information that is already exposed in an accessible manner. Examples include:" }} />
    </>
  ),
  timer: (
    <>
      <p dangerouslySetInnerHTML={{ __html: "The text contents of the timer <a href=\"#dfn-object\">object</a> indicate the current time measurement, and are updated as that amount changes. The timer value is not necessarily machine parsable, but authors <em>SHOULD</em> update the text contents at fixed intervals, except when the timer is paused or reaches an end-point." }} />
    </>
  ),
  toolbar: (
    <>
      <p dangerouslySetInnerHTML={{ __html: "The toolbar is often a subset of functions found in a <a href=\"https://w3c.github.io/aria/#menubar\"><code>menubar</code></a>, designed to reduce user effort in using these functions. Authors <em>MUST</em> supply a label on each toolbar when the application contains more than one toolbar." }} />
      <p dangerouslySetInnerHTML={{ __html: "Authors <em>MAY</em> manage focus of descendants for all instances of this <a href=\"#dfn-role\">role</a>, as described in <a href=\"#managingfocus\">Managing Focus</a>." }} />
      <p dangerouslySetInnerHTML={{ __html: "Elements with the role <code>toolbar</code> have an implicit <a href=\"https://w3c.github.io/aria/#aria-orientation\"><code>aria-orientation</code></a> value of <code>horizontal</code>." }} />
    </>
  ),
  tooltip: (
    <>
      <p dangerouslySetInnerHTML={{ __html: "The <code>tooltip</code> typically becomes visible, after a short delay, in response to a mouse hover, or after the <a href=\"#dfn-accessibility-parent\">accessibility parent</a> receives keyboard focus. The use of a <abbr title=\"Accessible Rich Internet Applications\">WAI-ARIA</abbr> tooltip is a supplement to the normal tooltip behavior of the user agent." }} />
    </>
  ),
  tree: (
    <>
      <p dangerouslySetInnerHTML={{ __html: "To be <a href=\"#dfn-keyboard-accessible\">keyboard accessible</a>, authors <em>SHOULD</em> manage focus of descendants for all instances of this <a href=\"#dfn-role\">role</a>, as described in <a href=\"#managingfocus\">Managing Focus</a>." }} />
      <p dangerouslySetInnerHTML={{ __html: "Elements with the role <code>tree</code> have an implicit <a href=\"https://w3c.github.io/aria/#aria-orientation\"><code>aria-orientation</code></a> value of <code>vertical</code>." }} />
    </>
  ),
  treegrid: (
    <>
      <p dangerouslySetInnerHTML={{ __html: "If <a href=\"https://w3c.github.io/aria/#aria-readonly\"><code>aria-readonly</code></a> is set on an <a href=\"https://dom.spec.whatwg.org/#concept-element\">element</a> with <a href=\"#dfn-role\">role</a> <code>treegrid</code>, <a href=\"https://infra.spec.whatwg.org/#user-agent\">user agents</a> <em>MUST</em> propagate the value to all <a href=\"https://w3c.github.io/aria/#gridcell\"><code>gridcell</code></a> elements that are <a href=\"#dfn-accessibility-descendant\">accessibility descendants</a> of the <code>treegrid</code> and expose the value in the accessibility <abbr title=\"Application Programming Interface\">API</abbr>. An author <em>MAY</em> override the propagated value of <a href=\"https://w3c.github.io/aria/#aria-readonly\"><code>aria-readonly</code></a> for an individual <a href=\"https://w3c.github.io/aria/#gridcell\"><code>gridcell</code></a> element." }} />
      <p dangerouslySetInnerHTML={{ __html: "When the <a href=\"https://w3c.github.io/aria/#aria-readonly\"><code>aria-readonly</code></a> attribute is applied to a <a href=\"#dfn-focusable\">focusable</a> <a href=\"https://w3c.github.io/aria/#gridcell\"><code>gridcell</code></a>, it indicates whether the content contained in the <a href=\"https://w3c.github.io/aria/#gridcell\"><code>gridcell</code></a> is editable. The <a href=\"https://w3c.github.io/aria/#aria-readonly\"><code>aria-readonly</code></a> attribute does not represent availability of functions for navigating or manipulating the <code>treegrid</code> itself." }} />
      <p dangerouslySetInnerHTML={{ __html: "In a <code>treegrid</code> that provides content editing functions, if the content of a focusable <a href=\"https://w3c.github.io/aria/#gridcell\"><code>gridcell</code></a> element is not editable, authors <em>MAY</em> set <a href=\"https://w3c.github.io/aria/#aria-readonly\"><code>aria-readonly</code></a> to <code>true</code> on the <a href=\"https://w3c.github.io/aria/#gridcell\"><code>gridcell</code></a> element. However, if a <code>treegrid</code> presents a collection of elements that do not support <a href=\"https://w3c.github.io/aria/#aria-readonly\"><code>aria-readonly</code></a>, such as a collection of <a href=\"https://w3c.github.io/aria/#link\"><code>link</code></a> elements, it is not necessary for the author to specify a value for <a href=\"https://w3c.github.io/aria/#aria-readonly\"><code>aria-readonly</code></a>." }} />
      <p dangerouslySetInnerHTML={{ __html: "To be <a href=\"#dfn-keyboard-accessible\">keyboard accessible</a>, authors <em>SHOULD</em> manage focus of descendants for all instances of this <a href=\"#dfn-role\">role</a>, as described in <a href=\"#managingfocus\">Managing Focus</a>." }} />
    </>
  ),
  treeitem: (
    <>
      <p dangerouslySetInnerHTML={{ __html: "A <a href=\"https://w3c.github.io/aria/#treeitem\"><code>treeitem</code></a> <a href=\"https://dom.spec.whatwg.org/#concept-element\">element</a> can contain a sub-level group of elements that can be expanded or collapsed. An expandable collection of <code>treeitem</code> elements are enclosed in an element with the <a href=\"https://w3c.github.io/aria/#group\"><code>group</code></a> <a href=\"#dfn-role\">role</a>." }} />
      <p dangerouslySetInnerHTML={{ __html: "Authors <em>MUST</em> ensure <a href=\"https://dom.spec.whatwg.org/#concept-element\">elements</a> with <a href=\"#dfn-role\">role</a> <code>treeitem</code> are <a href=\"#dfn-accessibility-child\">accessibility children</a> of an element with role <a href=\"https://w3c.github.io/aria/#tree\"><code>tree</code></a> or an element with role <a href=\"https://w3c.github.io/aria/#group\"><code>group</code></a> that is the <a href=\"#dfn-accessibility-child\">accessibility child</a> of an element with role <a href=\"https://w3c.github.io/aria/#treeitem\"><code>treeitem</code></a>." }} />
      <p dangerouslySetInnerHTML={{ __html: "In certain conditions, a user agent <em>MAY</em> provide an implicit value for <a href=\"https://w3c.github.io/aria/#aria-selected\"><code>aria-selected</code></a> for each <a href=\"https://w3c.github.io/aria/#treeitem\"><code>treeitem</code></a> in a <a href=\"https://w3c.github.io/aria/#tree\"><code>tree</code></a>, and if it does, the user agent <em>MUST</em> ensure the following conditions are met before providing an implicit value:" }} />
      <p dangerouslySetInnerHTML={{ __html: "If a user agent provides an implicit <a href=\"https://w3c.github.io/aria/#aria-selected\"><code>aria-selected</code></a> value for a <a href=\"https://w3c.github.io/aria/#treeitem\"><code>treeitem</code></a>, the value <em>SHOULD</em> be <code>true</code> if the <a href=\"https://w3c.github.io/aria/#treeitem\"><code>treeitem</code></a> has <abbr title=\"Document Object Model\">DOM</abbr> focus or the <a href=\"https://w3c.github.io/aria/#tree\"><code>tree</code></a> has <abbr title=\"Document Object Model\">DOM</abbr> focus and the <a href=\"https://w3c.github.io/aria/#treeitem\"><code>treeitem</code></a> is referenced by <a href=\"https://w3c.github.io/aria/#aria-activedescendant\"><code>aria-activedescendant</code></a>. Otherwise, if a user agent provides an implicit <a href=\"https://w3c.github.io/aria/#aria-selected\"><code>aria-selected</code></a> value for a <a href=\"https://w3c.github.io/aria/#treeitem\"><code>treeitem</code></a>, the value <em>SHOULD</em> be <code>false</code>." }} />
      <p dangerouslySetInnerHTML={{ __html: "Authors <em>MAY</em> indicate selection for <a href=\"https://w3c.github.io/aria/#treeitem\"><code>treeitem</code></a> elements using either <a href=\"https://w3c.github.io/aria/#aria-selected\"><code>aria-selected</code></a> or <a href=\"https://w3c.github.io/aria/#aria-checked\"><code>aria-checked</code></a>. Some user interfaces indicate selection with <a href=\"https://w3c.github.io/aria/#aria-selected\"><code>aria-selected</code></a> in single-select trees and with <a href=\"https://w3c.github.io/aria/#aria-checked\"><code>aria-checked</code></a> in multi-select trees. Authors <em>SHOULD NOT</em> specify both <a href=\"https://w3c.github.io/aria/#aria-selected\"><code>aria-selected</code></a> and <a href=\"https://w3c.github.io/aria/#aria-checked\"><code>aria-checked</code></a> on <a href=\"https://w3c.github.io/aria/#treeitem\"><code>treeitem</code></a> elements contained by the same <a href=\"https://w3c.github.io/aria/#tree\"><code>tree</code></a> except in the extremely rare circumstances where all the following conditions are met:" }} />
    </>
  ),
} as const;
